# Dijkstra's Algorithm

## The Conceptual Heart

Imagine you're a ripple expanding outward from a stone dropped in a pond — but the pond's surface is uneven. Some areas are thick with resistance, others thin. You always expand through the *path of least resistance* first.

That's Dijkstra. It's **greedy certainty** — once a node is "settled," you've found its absolute shortest path. You never revisit doubt.

---

## The Core Insight: A Promise of Finality

Think of each node holding a "best known distance" ticket. The algorithm works like a hospital triage system:

1. **Start** — give the source node a ticket reading `0`, everyone else `∞`
2. **Treat the most urgent** — always process the node with the *smallest* ticket
3. **Heal neighbors** — if traveling through the current node gives a neighbor a *better* ticket, update it
4. **Mark as resolved** — once treated, a node's ticket is *permanent*
5. **Repeat** until all nodes are resolved

The key intuition: *you can never improve a path to a settled node by going through an unsettled one*, because all future paths can only be equal or longer.

> ⚠️ This breaks with **negative edge weights** — a future node could secretly offer a shortcut backward. That's Bellman-Ford's territory.

---

## TypeScript Implementation

```typescript
// ─── Types ───────────────────────────────────────────────────────────────────

type NodeId = string | number;

interface Edge {
  to: NodeId;
  weight: number;
}

interface Graph {
  [node: NodeId]: Edge[];
}

interface ShortestPathResult {
  distances: Record<NodeId, number>;
  previous: Record<NodeId, NodeId | null>;
  getPath: (target: NodeId) => NodeId[];
}

// ─── Min-Priority Queue ───────────────────────────────────────────────────────
// A heap-based priority queue for O(log n) extraction vs O(n) for a naive array

class MinPriorityQueue {
  private heap: [number, NodeId][] = []; // [priority, nodeId]

  get size(): number {
    return this.heap.length;
  }

  enqueue(node: NodeId, priority: number): void {
    this.heap.push([priority, node]);
    this.bubbleUp(this.heap.length - 1);
  }

  dequeue(): [number, NodeId] | null {
    if (this.heap.length === 0) return null;

    const min = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return min;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent][0] <= this.heap[i][0]) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const length = this.heap.length;
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;

      if (left < length && this.heap[left][0] < this.heap[smallest][0])
        smallest = left;
      if (right < length && this.heap[right][0] < this.heap[smallest][0])
        smallest = right;
      if (smallest === i) break;

      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

function dijkstra(graph: Graph, source: NodeId): ShortestPathResult {
  const distances: Record<NodeId, number> = {};
  const previous: Record<NodeId, NodeId | null> = {};
  const settled = new Set<NodeId>();
  const pq = new MinPriorityQueue();

  // Initialize — every node is infinitely far away
  for (const node in graph) {
    distances[node] = Infinity;
    previous[node] = null;
  }

  // The source costs nothing to reach itself
  distances[source] = 0;
  pq.enqueue(source, 0);

  while (pq.size > 0) {
    const [currentDist, current] = pq.dequeue()!;

    // Skip stale entries (node was already settled with a better path)
    if (settled.has(current)) continue;
    settled.add(current);

    // Early exit: unreachable territory
    if (currentDist === Infinity) break;

    // Relax all outgoing edges
    for (const { to, weight } of graph[current] ?? []) {
      if (settled.has(to)) continue;

      const candidate = distances[current] + weight;

      if (candidate < distances[to]) {
        distances[to] = candidate;
        previous[to] = current;
        pq.enqueue(to, candidate); // Lazy deletion — old entry ignored when popped
      }
    }
  }

  // Reconstruct path by walking backwards through 'previous' pointers
  function getPath(target: NodeId): NodeId[] {
    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
      // Guard against cycles in malformed graphs
      if (path.length > Object.keys(graph).length + 1) break;
    }

    return path[0] === source ? path : []; // Empty = no path exists
  }

  return { distances, previous, getPath };
}

// ─── Example Usage ───────────────────────────────────────────────────────────

const cityMap: Graph = {
  A: [{ to: "B", weight: 4 }, { to: "C", weight: 2 }],
  B: [{ to: "C", weight: 1 }, { to: "D", weight: 5 }],
  C: [{ to: "B", weight: 1 }, { to: "D", weight: 8 }, { to: "E", weight: 10 }],
  D: [{ to: "E", weight: 2 }],
  E: [],
};

const { distances, getPath } = dijkstra(cityMap, "A");

console.log("Shortest distances from A:");
console.table(distances);
// A→0, B→3, C→2, D→8, E→10

console.log("\nShortest path A → E:", getPath("E").join(" → "));
// A → C → B → D → E
```

