      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ──────────────────────────────────────────────────────

function dijkstra(graph: Graph, source: string): DijkstraResult {
  const distances: Record<string, number> = {};
  const previous: Record<string, string | null> = {};
  const visited = new Set<string>();
  const pq = new MinHeap();

  // Initialize — all distances unknown (∞), except the source
  for (const node in graph) {
    distances[node] = Infinity;
    previous[node] = null;
  }
  distances[source] = 0;
  pq.push({ id: source, cost: 0 });

  while (pq.size > 0) {
    const { id: current, cost } = pq.pop()!;

    // Skip if we already found a better path (stale heap entry)
    if (visited.has(current)) continue;
    visited.add(current);

    // Early exit if we somehow only need one target (optional optimization)
    // if (current === target) break;

    for (const { to: neighbor, weight } of graph[current] ?? []) {
      if (visited.has(neighbor)) continue;

      const newCost = cost + weight;

      // Relaxation — the heart of Dijkstra
      if (newCost < distances[neighbor]) {
        distances[neighbor] = newCost;
        previous[neighbor] = current;
        pq.push({ id: neighbor, cost: newCost }); // lazy deletion strategy
      }
    }
  }

  // Reconstruct path by walking backwards through 'previous'
  function getPath(target: string): string[] {
    const path: string[] = [];
    let current: string | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
    }

    // If path doesn't start at source, no path exists
    return path[0] === source ? path : [];
  }

  return { distances, previous, getPath };
}

