```typescript
// --- Min-Heap Priority Queue ---
type HeapNode = { id: string; dist: number };

class MinHeap {
  private heap: HeapNode[] = [];

  get size() { return this.heap.length; }

  push(node: HeapNode): void {
    this.heap.push(node);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.heap.length === 0) return undefined;
    const top = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return top;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = (i - 1) >> 1;
      if (this.heap[parent].dist <= this.heap[i].dist) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const l = 2 * i + 1, r = 2 * i + 2;
      if (l < n && this.heap[l].dist < this.heap[smallest].dist) smallest = l;
      if (r < n && this.heap[r].dist < this.heap[smallest].dist) smallest = r;
      if (smallest === i) break;
      [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];
      i = smallest;
    }
  }
}

// --- Graph Types ---
type Edge = { to: string; weight: number };
type Graph = Map<string, Edge[]>;

// --- Dijkstra ---
interface DijkstraResult {
  distances: Map<string, number>;
  previous: Map<string, string | null>;
  getPath(target: string): string[];
}

function dijkstra(graph: Graph, source: string): DijkstraResult {
  const distances = new Map<string, number>();
  const previous = new Map<string, string | null>();
  const visited = new Set<string>();
  const pq = new MinHeap();

  // Initialize all distances to Infinity
  for (const node of graph.keys()) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }
  distances.set(source, 0);
  pq.push({ id: source, dist: 0 });

  while (pq.size > 0) {
    const { id: u, dist: d } = pq.pop()!;

    // Stale entry in the heap — skip
    if (visited.has(u)) continue;
    visited.add(u);

    const neighbors = graph.get(u) ?? [];
    for (const { to: v, weight } of neighbors) {
      if (visited.has(v)) continue;
      const newDist = d + weight;
      if (newDist < distances.get(v)!) {
        distances.set(v, newDist);
        previous.set(v, u);
        pq.push({ id: v, dist: newDist });
      }
    }
  }

  return {
    distances,
    previous,
    getPath(target: string): string[] {
      const path: string[] = [];
      let cur: string | null = target;
      while (cur !== null) {
        path.unshift(cur);
        cur = previous.get(cur) ?? null;
        if (cur === source) { path.unshift(cur); break; }
      }
      return distances.get(target) === Infinity ? [] : path;
    },
  };
}

