    return min;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[parent].priority <= this.heap[index].priority) break;
      [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
      index = parent;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left  = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left  < length && this.heap[left].priority  < this.heap[smallest].priority) smallest = left;
      if (right < length && this.heap[right].priority < this.heap[smallest].priority) smallest = right;

      if (smallest === index) break;

      [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
      index = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

/**
 * Finds shortest paths from `source` to all nodes in a weighted graph.
 *
 * @param graph    - Adjacency list: graph[u] = [{ to, weight }, ...]
 * @param source   - Starting node index
 * @returns        - Distances, predecessors, and a path-reconstruction helper
 */
function dijkstra(graph: Edge[][], source: number): DijkstraResult {
  const V = graph.length;
  const distances: number[]       = new Array(V).fill(Infinity);
  const predecessors: (number | null)[] = new Array(V).fill(null);
  const visited: boolean[]        = new Array(V).fill(false);

  distances[source] = 0;

  const pq = new MinHeap();
  pq.push({ id: source, priority: 0 });

  while (!pq.isEmpty()) {
    const { id: u, priority: d } = pq.pop()!;

    // Skip stale entries (lazy deletion approach)
    if (visited[u]) continue;
    visited[u] = true;

    // Early exit if distance is already worse than recorded
    if (d > distances[u]) continue;

    for (const { to: v, weight } of graph[u]) {
      if (visited[v]) continue;

      const candidate = distances[u] + weight;

      if (candidate < distances[v]) {
        distances[v]    = candidate;
        predecessors[v] = u;
        pq.push({ id: v, priority: candidate });
      }
    }
  }

  // Reconstruct the path from source to a given target
  const getPath = (target: number): number[] | null => {
    if (distances[target] === Infinity) return null; // unreachable

    const path: number[] = [];
    let current: number | null = target;

    while (current !== null) {
      path.unshift(current);
      current = predecessors[current];
    }

    return path[0] === source ? path : null;
  };

  return { distances, predecessors, getPath };
}

