function dijkstra(graph: Graph, start: NodeId): DijkstraResult {
  const distances = new Map<NodeId, number>();
  const previous  = new Map<NodeId, NodeId | null>();
  const visited   = new Set<NodeId>();
  const queue     = new MinHeap();

  // Initialize all nodes as unreachable
  for (const node of Object.keys(graph)) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }

  // The start costs nothing to reach
  distances.set(start, 0);
  queue.push({ id: start, cost: 0 });

  while (queue.size > 0) {
    const { id: current, cost: currentCost } = queue.pop()!;

    // Skip if we already found a better path (stale queue entry)
    if (visited.has(current)) continue;
    visited.add(current);

    // No point continuing if we're already at infinity
    if (currentCost === Infinity) break;

    for (const edge of graph[current] ?? []) {
      if (visited.has(edge.to)) continue;

      const newDist = currentCost + edge.weight;

      // Relaxation: is this path cheaper than what we knew?
      if (newDist < distances.get(edge.to)!) {
        distances.set(edge.to, newDist);
        previous.set(edge.to, current);
        queue.push({ id: edge.to, cost: newDist });
      }
    }
  }

  // Path reconstruction — walk backwards through 'previous'
  function getPath(target: NodeId): NodeId[] | null {
    if (!distances.has(target) || distances.get(target) === Infinity) {
      return null; // unreachable
    }

    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous.get(current) ?? null;
    }

    return path[0] === start ? path : null;
  }

  return { distances, previous, getPath };
}

