/**
 * Finds shortest paths from a source node to all other nodes.
 *
 * @param graph  - Adjacency list: graph[u] = [{ to: v, weight: w }, ...]
 * @param source - Starting node index
 * @returns distances and previous-node arrays for path reconstruction
 */
function dijkstra(graph: Edge[][], source: number): ShortestPathResult {
  const n = graph.length;
  const distances = new Array<number>(n).fill(Infinity);
  const previous = new Array<number | null>(n).fill(null);
  const visited = new Array<boolean>(n).fill(false);

  distances[source] = 0;

  const pq = new MinHeap();
  pq.push({ node: source, distance: 0 });

  while (pq.size > 0) {
    const { node: u, distance: d } = pq.pop()!;

    // Skip if we've already finalized a shorter path to u
    if (visited[u]) continue;
    visited[u] = true;

    // Early exit if recorded distance is outdated (stale entry in heap)
    if (d > distances[u]) continue;

    for (const { to: v, weight } of graph[u]) {
      if (visited[v]) continue;

      const newDist = distances[u] + weight;

      // Relaxation step
      if (newDist < distances[v]) {
        distances[v] = newDist;
        previous[v] = u;
        pq.push({ node: v, distance: newDist });
      }
    }
  }

  return { distances, previous };
}

