function dijkstra(graph: Edge[][], source: number): DijkstraResult {
  const n = graph.length;
  const distances = new Array<number>(n).fill(Infinity);
  const previous = new Array<number | null>(n).fill(null);
  const visited = new Set<number>();

  distances[source] = 0;

  const pq = new MinHeap();
  pq.push(0, source);

  while (pq.size > 0) {
    const [currentDist, current] = pq.pop()!;

    // Skip if we've already found a better path (stale entry)
    if (visited.has(current)) continue;
    visited.add(current);

    for (const { to, weight } of graph[current]) {
      if (visited.has(to)) continue;

      const newDist = currentDist + weight;

      if (newDist < distances[to]) {
        distances[to] = newDist;
        previous[to] = current;
        pq.push(newDist, to); // Push updated distance (lazy deletion)
      }
    }
