class Graph {
  private adjacencyList: Map<number, Edge[]> = new Map();
  private nodeCount: number;

  constructor(nodeCount: number) {
    this.nodeCount = nodeCount;
    for (let i = 0; i < nodeCount; i++) {
      this.adjacencyList.set(i, []);
    }
  }

  /**
   * Add a directed edge from → to with the given weight.
   * Call twice (swapping from/to) for undirected graphs.
   */
  addEdge(from: number, to: number, weight: number): void {
    if (weight < 0) throw new Error("Dijkstra requires non-negative weights");
    this.adjacencyList.get(from)!.push({ to, weight });
  }

  addUndirectedEdge(a: number, b: number, weight: number): void {
    this.addEdge(a, b, weight);
    this.addEdge(b, a, weight);
  }

  neighbors(node: number): Edge[] {
    return this.adjacencyList.get(node) ?? [];
  }

  get size(): number {
    return this.nodeCount;
  }
}

