  const pq = new MinPriorityQueue();
  pq.enqueue(source, 0);

  while (!pq.isEmpty()) {
    const { node: u, priority: distU } = pq.dequeue();

    // Skip stale entries (lazy deletion — we don't decrease-key, we re-insert)
    if (settled[u]) continue;
    settled[u] = true;

    // Early exit: all reachable nodes settled
    if (distU === INF) break;

    for (const { to: v, weight } of graph.neighbors(u)) {
      if (settled[v]) continue;

      const newDist = distances[u] + weight;

      if (newDist < distances[v]) {
        distances[v] = newDist;
        previous[v]  = u;
        pq.enqueue(v, newDist); // lazy re-insert instead of decrease-key
      }
    }
  }

  return { distances, previous };
}

// ─── Path Reconstruction ──────────────────────────────────────────────────────

function reconstructPath(
  previous: (number | null)[],
  source: number,
  target: number
): number[] | null {
  const path: number[] = [];
  let current: number | null = target;

  while (current !== null) {
    path.unshift(current);
    if (current === source) return path;
    current = previous[current];
  }

  return null; // target is unreachable
}

