**Core idea:** Greedily expand the nearest unvisited node. Since edge weights are non-negative, the first time you reach a node is guaranteed to be via the shortest path.

**Steps:**
1. Set source distance to 0, all others to ∞
2. Use a min-heap (priority queue) keyed by current best distance
3. Pop the nearest node, mark it visited
4. For each neighbor, if `current_dist + edge_weight < known_dist`, relax it (update and push to heap)
5. Stale heap entries for already-visited nodes are skipped

**Complexity:** O((V + E) log V) with a binary heap.

**Why it works:** The min-heap invariant means when you pop a node, no future path can beat it — any alternative route would have to pass through an unvisited node at least as far away, then add more non-negative weight.

---

```typescript
type Edge = { to: string; weight: number };
type Graph = Map<string, Edge[]>;

class MinHeap<T> {
  private data: Array<[number, T]> = [];

  push(priority: number, value: T): void {
    this.data.push([priority, value]);
    this.bubbleUp(this.data.length - 1);
  }

  pop(): [number, T] | undefined {
    if (this.data.length === 0) return undefined;
    const top = this.data[0];
    const last = this.data.pop()!;
    if (this.data.length > 0) {
      this.data[0] = last;
      this.sinkDown(0);
    }
    return top;
  }

  get size() { return this.data.length; }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.data[parent][0] <= this.data[i][0]) break;
      [this.data[parent], this.data[i]] = [this.data[i], this.data[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.data.length;
    while (true) {
      let min = i;
      const l = 2 * i + 1, r = 2 * i + 2;
      if (l < n && this.data[l][0] < this.data[min][0]) min = l;
      if (r < n && this.data[r][0] < this.data[min][0]) min = r;
      if (min === i) break;
      [this.data[i], this.data[min]] = [this.data[min], this.data[i]];
      i = min;
    }
  }
}

function dijkstra(graph: Graph, source: string): {
  distances: Map<string, number>;
  previous: Map<string, string | null>;
} {
  const distances = new Map<string, number>();
  const previous = new Map<string, string | null>();
  const visited = new Set<string>();
  const heap = new MinHeap<string>();

  for (const node of graph.keys()) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }
  distances.set(source, 0);
  heap.push(0, source);

  while (heap.size > 0) {
    const [d, u] = heap.pop()!;
    if (visited.has(u)) continue;
    visited.add(u);

    for (const { to, weight } of graph.get(u) ?? []) {
      const alt = d + weight;
      if (alt < distances.get(to)!) {
        distances.set(to, alt);
        previous.set(to, u);
        heap.push(alt, to);
      }
    }
  }

  return { distances, previous };
}

function getPath(previous: Map<string, string | null>, target: string): string[] {
  const path: string[] = [];
  let node: string | null = target;
  while (node !== null) {
    path.unshift(node);
    node = previous.get(node) ?? null;
  }
  return path;
}

// Example
const graph: Graph = new Map([
  ["A", [{ to: "B", weight: 1 }, { to: "C", weight: 4 }]],
  ["B", [{ to: "C", weight: 2 }, { to: "D", weight: 5 }]],
  ["C", [{ to: "D", weight: 1 }]],
  ["D", []],
]);

const { distances, previous } = dijkstra(graph, "A");
console.log(distances);           // A→0, B→1, C→3, D→4
console.log(getPath(previous, "D")); // ["A", "B", "C", "D"]
```

The `previous` map enables path reconstruction by backtracking from target to source. Stale heap entries (from relaxations later superseded) are harmlessly discarded by the `visited` check.

## Dijkstra's Algorithm

**Core idea:** Find the shortest path from a source node to all others in a graph with non-negative edge weights. It's greedy: always extend the cheapest known path next.

**Key invariant:** When a node is "settled" (popped from the priority queue with the minimum cost), its distance is final. No later path can improve it because all weights are ≥ 0.

**Steps:**
1. Initialize all distances to ∞, source to 0.
2. Push source into a min-priority queue keyed by distance.
3. Pop the minimum-distance node `u`. If already visited, skip.
4. For each neighbor `v` of `u`: if `dist[u] + weight(u,v) < dist[v]`, update `dist[v]` and push `v` into the queue.
5. Repeat until queue is empty.

**Complexity:** O((V + E) log V) with a binary heap.

---

```typescript
type Edge = { to: number; weight: number };
type Graph = Map<number, Edge[]>;

// Binary min-heap keyed on [priority, value]
class MinHeap {
  private data: [number, number][] = [];

  push(priority: number, value: number) {
    this.data.push([priority, value]);
    this.bubbleUp(this.data.length - 1);
  }

  pop(): [number, number] | undefined {
    if (this.data.length === 0) return undefined;
    const top = this.data[0];
    const last = this.data.pop()!;
    if (this.data.length > 0) {
      this.data[0] = last;
      this.sinkDown(0);
    }
    return top;
  }

  get size() { return this.data.length; }

  private bubbleUp(i: number) {
    while (i > 0) {
      const parent = (i - 1) >> 1;
      if (this.data[parent][0] <= this.data[i][0]) break;
      [this.data[parent], this.data[i]] = [this.data[i], this.data[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number) {
    const n = this.data.length;
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;
      if (left < n && this.data[left][0] < this.data[smallest][0]) smallest = left;
      if (right < n && this.data[right][0] < this.data[smallest][0]) smallest = right;
      if (smallest === i) break;
      [this.data[smallest], this.data[i]] = [this.data[i], this.data[smallest]];
      i = smallest;
    }
  }
}

function dijkstra(
  graph: Graph,
  source: number,
): { dist: Map<number, number>; prev: Map<number, number | null> } {
  const dist = new Map<number, number>();
  const prev = new Map<number, number | null>();
  const visited = new Set<number>();
  const heap = new MinHeap();

  for (const node of graph.keys()) {
    dist.set(node, Infinity);
    prev.set(node, null);
  }
  dist.set(source, 0);
  heap.push(0, source);

  while (heap.size > 0) {
    const [d, u] = heap.pop()!;
    if (visited.has(u)) continue;
    visited.add(u);

    for (const { to, weight } of graph.get(u) ?? []) {
      const candidate = d + weight;
      if (candidate < dist.get(to)!) {
        dist.set(to, candidate);
        prev.set(to, u);
        heap.push(candidate, to);
      }
    }
  }

  return { dist, prev };
}

function reconstructPath(prev: Map<number, number | null>, target: number): number[] {
  const path: number[] = [];
  let current: number | null = target;
  while (current !== null) {
    path.unshift(current);
    current = prev.get(current) ?? null;
  }
  return path;
}

// --- Example ---
const graph: Graph = new Map([
  [0, [{ to: 1, weight: 4 }, { to: 2, weight: 1 }]],
  [1, [{ to: 3, weight: 1 }]],
  [2, [{ to: 1, weight: 2 }, { to: 3, weight: 5 }]],
  [3, []],
]);

const { dist, prev } = dijkstra(graph, 0);

console.log("Distances from node 0:", Object.fromEntries(dist));
// { 0: 0, 1: 3, 2: 1, 3: 4 }

console.log("Shortest path to node 3:", reconstructPath(prev, 3));
