interface Edge {
  to: number;
  weight: number;
}

interface ShortestPathResult {
  distances: number[];          // distances[i] = shortest distance from source to i
  previous: (number | null)[];  // previous[i] = predecessor of i on shortest path
  getPath: (target: number) => number[] | null; // reconstruct a specific path
}

// ─── Min-Heap (Priority Queue) ────────────────────────────────────────────────

class MinHeap {
  private heap: [number, number][] = []; // [distance, nodeId]

  get size(): number {
    return this.heap.length;
  }

  push(distance: number, node: number): void {
    this.heap.push([distance, node]);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): [number, number] | null {
    if (this.heap.length === 0) return null;
    const min = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return min;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent][0] <= this.heap[i][0]) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;

      if (left < n && this.heap[left][0] < this.heap[smallest][0]) {
        smallest = left;
      }
      if (right < n && this.heap[right][0] < this.heap[smallest][0]) {
        smallest = right;
      }
      if (smallest === i) break;

      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Graph ────────────────────────────────────────────────────────────────────

class Graph {
  private adjacency: Map<number, Edge[]> = new Map();
  private nodeCount: number;

  constructor(nodeCount: number) {
    this.nodeCount = nodeCount;
    for (let i = 0; i < nodeCount; i++) {
      this.adjacency.set(i, []);
    }
  }

  addEdge(from: number, to: number, weight: number, directed = false): void {
    if (weight < 0) throw new Error("Dijkstra requires non-negative edge weights.");

    this.adjacency.get(from)!.push({ to, weight });
    if (!directed) {
      this.adjacency.get(to)!.push({ to: from, weight });
    }
  }

  dijkstra(source: number): ShortestPathResult {
    if (source < 0 || source >= this.nodeCount) {
      throw new Error(`Source node ${source} is out of range.`);
    }

    const distances = new Array<number>(this.nodeCount).fill(Infinity);
    const previous = new Array<number | null>(this.nodeCount).fill(null);
    const settled = new Set<number>();

    distances[source] = 0;

    const pq = new MinHeap();
    pq.push(0, source);

    while (pq.size > 0) {
      const [currentDist, u] = pq.pop()!;

      // Skip if we already found a better path (stale entry in heap)
      if (settled.has(u)) continue;
      settled.add(u);

      // Early exit: remaining nodes are unreachable or fully settled
      if (currentDist === Infinity) break;

      for (const { to: v, weight } of this.adjacency.get(u) ?? []) {
        if (settled.has(v)) continue;

        const newDist = distances[u] + weight;
        if (newDist < distances[v]) {
          distances[v] = newDist;
          previous[v] = u;
          pq.push(newDist, v); // Insert updated distance (lazy deletion)
        }
      }
    }

    // Path reconstruction closure
    const getPath = (target: number): number[] | null => {
      if (distances[target] === Infinity) return null; // unreachable

      const path: number[] = [];
      let current: number | null = target;
      while (current !== null) {
        path.unshift(current);
        current = previous[current];
      }
      return path[0] === source ? path : null;
    };

    return { distances, previous, getPath };
  }
}

