// ─────────────────────────────────────────────
//  Types
// ─────────────────────────────────────────────

type NodeId = string | number;

interface Edge {
  to: NodeId;
  weight: number;
}

interface Graph {
  [node: NodeId]: Edge[];
}

interface ShortestPathResult {
  distances: Map<NodeId, number>;
  previous: Map<NodeId, NodeId | null>;
  getPath: (target: NodeId) => NodeId[];
}

// ─────────────────────────────────────────────
//  Minimal Priority Queue (Min-Heap)
// ─────────────────────────────────────────────

interface PQNode {
  id: NodeId;
  priority: number;
}

class MinPriorityQueue {
  private heap: PQNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  enqueue(id: NodeId, priority: number): void {
    this.heap.push({ id, priority });
    this.bubbleUp(this.heap.length - 1);
  }

  dequeue(): PQNode | undefined {
    if (this.heap.length === 0) return undefined;
    const min = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return min;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent].priority <= this.heap[i].priority) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const length = this.heap.length;
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;
      if (left < length && this.heap[left].priority < this.heap[smallest].priority)
        smallest = left;
      if (right < length && this.heap[right].priority < this.heap[smallest].priority)
        smallest = right;
      if (smallest === i) break;
      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─────────────────────────────────────────────
//  Dijkstra's Algorithm
// ─────────────────────────────────────────────

function dijkstra(graph: Graph, source: NodeId): ShortestPathResult {
  const distances = new Map<NodeId, number>();
  const previous = new Map<NodeId, NodeId | null>();
  const visited = new Set<NodeId>();
  const pq = new MinPriorityQueue();

  // Initialize all known nodes with Infinity
  for (const node of Object.keys(graph)) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }

  // The source costs nothing to reach
  distances.set(source, 0);
  pq.enqueue(source, 0);

  while (pq.size > 0) {
    const { id: current } = pq.dequeue()!;

    // A visited node's shortest path is already finalized
    if (visited.has(current)) continue;
    visited.add(current);

    const neighbors = graph[current] ?? [];

    for (const { to, weight } of neighbors) {
      if (visited.has(to)) continue;

      // The heart of Dijkstra: relaxation
      const candidate = distances.get(current)! + weight;
      if (candidate < (distances.get(to) ?? Infinity)) {
        distances.set(to, candidate);
        previous.set(to, current);
        pq.enqueue(to, candidate); // Lazy deletion: old entries become stale
      }
    }
  }

  // Reconstruct path by walking backwards through `previous`
  function getPath(target: NodeId): NodeId[] {
    const path: NodeId[] = [];
    let current: NodeId | null = target;
    while (current !== null) {
      path.unshift(current);
      current = previous.get(current) ?? null;
    }
    // Return empty array if no valid path exists
    return path[0] === source ? path : [];
  }

  return { distances, previous, getPath };
}

