  C: [{ to: "B", weight: 2 }, { to: "D", weight: 5 }],
  D: [],
};

const result = dijkstra(graph, "A");

console.log("=== Shortest Distances from A ===");
result.distances.forEach((dist, node) => {
  console.log(`  A → ${node}: ${dist === Infinity ? "unreachable" : dist}`);
});

console.log("\n=== Shortest Paths ===");
for (const node of ["B", "C", "D"]) {
  const path = result.getPath(node);
  console.log(`  A → ${node}: [${path.join(" → ")}]`);
}
