// (O(log n) extraction — the engine of efficient Dijkstra)
// ============================================================

interface HeapNode {
  node: string;
  distance: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  /** Insert a node with its priority (distance) */
  insert(node: string, distance: number): void {
    this.heap.push({ node, distance });
    this.bubbleUp(this.heap.length - 1);
  }

  /** Remove and return the node with the smallest distance */
  extractMin(): HeapNode {
    if (this.isEmpty()) throw new Error("Heap is empty");

    const min = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return min;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parentIdx = Math.floor((index - 1) / 2);
      if (this.heap[parentIdx].distance <= this.heap[index].distance) break;

      // Swap with parent
      [this.heap[parentIdx], this.heap[index]] =
        [this.heap[index], this.heap[parentIdx]];
      index = parentIdx;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left  = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left  < length && this.heap[left].distance  < this.heap[smallest].distance) {
        smallest = left;
      }
      if (right < length && this.heap[right].distance < this.heap[smallest].distance) {
        smallest = right;
      }
      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] =
        [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

