function addEdge(
  graph: Graph,
  from: string,
  to: string,
  weight: number,
  undirected = true   // default: undirected graph
): void {
  if (weight < 0) throw new Error(`Negative weight not allowed: ${weight}`);

  if (!graph.has(from)) graph.set(from, []);
  if (!graph.has(to))   graph.set(to,   []);

  graph.get(from)!.push({ to, weight });
  if (undirected) {
    graph.get(to)!.push({ to: from, weight });
  }
}

