interface Edge {
  to: number;
  weight: number;
}

interface DijkstraResult {
  distances: number[];
  predecessors: (number | null)[];
  getPath: (target: number) => number[] | null;
}

// ─── Min-Priority Queue ───────────────────────────────────────────────────────

class MinHeap {
  private heap: [number, number][] = []; // [distance, node]

  get size(): number {
    return this.heap.length;
  }

  push(distance: number, node: number): void {
    this.heap.push([distance, node]);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): [number, number] | null {
    if (this.heap.length === 0) return null;

    const min = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return min;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent][0] <= this.heap[i][0]) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;

    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;

      if (left < n && this.heap[left][0] < this.heap[smallest][0]) {
        smallest = left;
      }
      if (right < n && this.heap[right][0] < this.heap[smallest][0]) {
        smallest = right;
      }
      if (smallest === i) break;

      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Graph ────────────────────────────────────────────────────────────────────

class Graph {
  private adjacencyList: Map<number, Edge[]> = new Map();

  addNode(node: number): void {
    if (!this.adjacencyList.has(node)) {
      this.adjacencyList.set(node, []);
    }
  }

  addEdge(from: number, to: number, weight: number, undirected = true): void {
    if (weight < 0) throw new Error("Dijkstra requires non-negative weights.");

    this.addNode(from);
    this.addNode(to);

    this.adjacencyList.get(from)!.push({ to, weight });
    if (undirected) {
      this.adjacencyList.get(to)!.push({ to: from, weight });
    }
  }

  getNodes(): number[] {
    return [...this.adjacencyList.keys()];
  }

  getNeighbors(node: number): Edge[] {
    return this.adjacencyList.get(node) ?? [];
  }
}

// ─── Dijkstra ─────────────────────────────────────────────────────────────────

function dijkstra(graph: Graph, source: number): DijkstraResult {
  const nodes = graph.getNodes();
  const INF = Infinity;

  // Initialize distances and predecessors
  const distances: Map<number, number> = new Map();
  const predecessors: Map<number, number | null> = new Map();
  const visited: Set<number> = new Set();

  for (const node of nodes) {
    distances.set(node, INF);
    predecessors.set(node, null);
  }
  distances.set(source, 0);

  // Seed the priority queue with the source
  const pq = new MinHeap();
  pq.push(0, source);

  while (pq.size > 0) {
    const [currentDist, current] = pq.pop()!;

    // Skip stale entries (node was already settled with a shorter path)
    if (visited.has(current)) continue;
    visited.add(current);

    // Early exit: remaining distances can only be larger
    if (currentDist === INF) break;

    // Relax neighbors
    for (const { to, weight } of graph.getNeighbors(current)) {
      if (visited.has(to)) continue;

      const newDist = currentDist + weight;

      if (newDist < distances.get(to)!) {
        distances.set(to, newDist);
        predecessors.set(to, current);
        pq.push(newDist, to); // Push updated entry; stale old entry ignored via visited check
      }
    }
  }

  // ── Path reconstruction helper ──────────────────────────────────────────────
  function getPath(target: number): number[] | null {
    if (distances.get(target) === INF) return null; // Unreachable

    const path: number[] = [];
    let current: number | null = target;

    while (current !== null) {
      path.unshift(current);
      current = predecessors.get(current) ?? null;
    }

    return path[0] === source ? path : null;
  }

  return {
    distances: nodes.map((n) => distances.get(n)!),
    predecessors: nodes.map((n) => predecessors.get(n)!),
    getPath,
  };
}

