// ─── Min-Priority Queue ───────────────────────────────────────────────────────

interface PQNode {
  id: string;
  priority: number;
}

class MinPriorityQueue {
  private heap: PQNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  enqueue(id: string, priority: number): void {
    this.heap.push({ id, priority });
    this.bubbleUp(this.heap.length - 1);
  }

  dequeue(): PQNode {
    if (this.isEmpty()) throw new Error("Queue is empty");

    const min = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return min;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[parent].priority <= this.heap[index].priority) break;
      [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
      index = parent;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left  = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left  < length && this.heap[left].priority  < this.heap[smallest].priority) smallest = left;
      if (right < length && this.heap[right].priority < this.heap[smallest].priority) smallest = right;

      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

function dijkstra(graph: Graph, source: string): ShortestPathResult {
  if (!graph.has(source)) {
    throw new Error(`Source node "${source}" not found in graph`);
  }

  const distances = new Map<string, number>();
  const previous  = new Map<string, string | null>();
  const finalized = new Set<string>();
  const pq        = new MinPriorityQueue();

  // Initialize all nodes
  for (const node of graph.keys()) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }

  // Source node setup
  distances.set(source, 0);
  pq.enqueue(source, 0);

  while (!pq.isEmpty()) {
    const { id: current, priority: currentDist } = pq.dequeue();

    // Skip stale entries (lazy deletion pattern)
    if (finalized.has(current)) continue;
    finalized.add(current);

    // Early exit if we somehow exceed known distance (shouldn't happen)
    if (currentDist > distances.get(current)!) continue;

    const neighbors = graph.get(current) ?? [];

    for (const { to: neighbor, weight } of neighbors) {
      if (finalized.has(neighbor)) continue;
      if (weight < 0) throw new Error("Negative edge weights are not supported");

      const newDist = distances.get(current)! + weight;

      if (newDist < (distances.get(neighbor) ?? Infinity)) {
        distances.set(neighbor, newDist);
        previous.set(neighbor, current);
        pq.enqueue(neighbor, newDist);  // Lazy: push duplicate, skip when popped
      }
    }
  }

  // Path reconstruction helper
  function getPath(target: string): string[] | null {
    if (!distances.has(target) || distances.get(target) === Infinity) {
      return null; // Unreachable
    }

    const path: string[] = [];
    let current: string | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous.get(current) ?? null;
    }

    // Verify path actually starts at source
    return path[0] === source ? path : null;
  }

  return { distances, previous, getPath };
}

// ─── Graph Builder Helper ─────────────────────────────────────────────────────

function buildGraph(
  edges: Array<[string, string, number]>,
  directed = false
): Graph {
  const graph: Graph = new Map();

  const addEdge = (from: string, to: string, weight: number) => {
    if (!graph.has(from)) graph.set(from, []);
    if (!graph.has(to))   graph.set(to,   []); // Ensure node exists
    graph.get(from)!.push({ to, weight });
  };

  for (const [from, to, weight] of edges) {
    addEdge(from, to, weight);
    if (!directed) addEdge(to, from, weight);
  }

  return graph;
}

