  previous: Record<NodeId, NodeId | null>;
  getPath: (target: NodeId) => NodeId[];
}

// ─── Min-Heap Priority Queue ───────────────────────────────────────────────────

interface HeapNode {
  id: NodeId;
  priority: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  push(node: HeapNode): void {
    this.heap.push(node);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.heap.length === 0) return undefined;
    const min = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return min;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent].priority <= this.heap[i].priority) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;

      if (left < n && this.heap[left].priority < this.heap[smallest].priority)
        smallest = left;
      if (right < n && this.heap[right].priority < this.heap[smallest].priority)
        smallest = right;
      if (smallest === i) break;

      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

function dijkstra(graph: Graph, source: NodeId): ShortestPathResult {
  const distances: Record<NodeId, number> = {};
  const previous: Record<NodeId, NodeId | null> = {};
  const settled = new Set<NodeId>();
  const queue = new MinHeap();

  // Initialize all nodes
  for (const node of Object.keys(graph)) {
    distances[node] = Infinity;
    previous[node] = null;
  }

  distances[source] = 0;
  queue.push({ id: source, priority: 0 });

  while (queue.size > 0) {
    const { id: current } = queue.pop()!;

    // Skip if already settled (stale heap entry)
    if (settled.has(current)) continue;
    settled.add(current);

    for (const edge of graph[current] ?? []) {
      if (settled.has(edge.to)) continue;

      const candidate = distances[current] + edge.weight;

      // Relaxation — found a better path!
      if (candidate < distances[edge.to]) {
        distances[edge.to] = candidate;
        previous[edge.to] = current;
        queue.push({ id: edge.to, priority: candidate });
      }
    }
  }

  // Reconstruct path by walking the `previous` chain
  const getPath = (target: NodeId): NodeId[] => {
    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
      // Detect disconnected node
      if (current !== null && !(current in previous)) break;
    }

    return path[0] === source ? path : []; // empty = no path exists
  };

  return { distances, previous, getPath };
}

