  }

  push(node: HeapNode): void {
    this.heap.push(node);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.heap.length === 0) return undefined;

    const top = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return top;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = (i - 1) >> 1; // Math.floor((i - 1) / 2)
      if (this.heap[parent].dist <= this.heap[i].dist) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const left  = 2 * i + 1;
      const right = 2 * i + 2;

      if (left  < n && this.heap[left].dist  < this.heap[smallest].dist) smallest = left;
      if (right < n && this.heap[right].dist < this.heap[smallest].dist) smallest = right;

      if (smallest === i) break;

      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ──────────────────────────────────────────────────────

function dijkstra(
  graph: Edge[][],  // adjacency list: graph[u] = [{to, weight}, ...]
  source: number
): DijkstraResult {
  const V = graph.length;
  const distances = new Array<number>(V).fill(Infinity);
  const previous  = new Array<number | null>(V).fill(null);
  const settled   = new Array<boolean>(V).fill(false);

  distances[source] = 0;

  const pq = new MinHeap();
  pq.push({ id: source, dist: 0 });

  while (pq.size > 0) {
    const { id: u, dist: distU } = pq.pop()!;

    // Stale entry — a shorter path was already found
    if (settled[u]) continue;
    settled[u] = true;

    // Early termination is possible here if targeting a single node

    for (const { to: v, weight } of graph[u]) {
      if (settled[v]) continue;

      const candidate = distU + weight;
      if (candidate < distances[v]) {
        distances[v] = candidate;
        previous[v]  = u;
        pq.push({ id: v, dist: candidate }); // lazy deletion approach
      }
    }
  }

  // Reconstruct path from source to target
  function getPath(target: number): number[] | null {
    if (distances[target] === Infinity) return null; // unreachable

    const path: number[] = [];
    let current: number | null = target;

    while (current !== null) {
      path.push(current);
      current = previous[current];
    }

    return path.reverse();
  }

  return { distances, previous, getPath };
}

// ─── Helper: Build Graph ───────────────────────────────────────────────────────

function buildGraph(
  numNodes: number,
  edges: [number, number, number][] // [from, to, weight]
): Edge[][] {
  const graph: Edge[][] = Array.from({ length: numNodes }, () => []);

  for (const [from, to, weight] of edges) {
    graph[from].push({ to, weight });
    graph[to].push({ to: from, weight }); // remove for directed graphs
  }

  return graph;
}

