  const distances: Record<NodeId, number> = {};
  const previous: Record<NodeId, NodeId | null> = {};
  const visited = new Set<NodeId>();
  const pq = new MinHeap();

  // Initialize all distances to Infinity
  for (const node in graph) {
    distances[node] = Infinity;
    previous[node] = null;
  }

  // Source distance is 0
  distances[source] = 0;
  pq.insert({ id: source, priority: 0 });

  while (!pq.isEmpty()) {
    const current = pq.extractMin()!;
    const { id: currentId } = current;

    // Skip if already visited (stale entry in heap)
    if (visited.has(currentId)) continue;
    visited.add(currentId);

    const neighbors = graph[currentId] ?? [];

    for (const edge of neighbors) {
      if (visited.has(edge.to)) continue;

      const newDist = distances[currentId] + edge.weight;

      if (newDist < distances[edge.to]) {
        distances[edge.to] = newDist;
        previous[edge.to] = currentId;
        pq.insert({ id: edge.to, priority: newDist });
      }
    }
  }

