  function getShortestPath(target: NodeId): NodeId[] {
    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current];
    }

    // If path doesn't start with source, no path exists
    if (path[0] !== source) return [];
    return path;
  }

  return { distances, previous, getShortestPath };
}

