// ============================================================
// Dijkstra's Shortest Path Algorithm — TypeScript Implementation
// ============================================================

type Graph = Map<string, Map<string, number>>;

interface DijkstraResult {
  distances: Map<string, number>;
  previousNodes: Map<string, string | null>;
  path: string[];
  totalCost: number;
}

// ------------------------------------------------------------
// Priority Queue (Min-Heap) for efficient node selection
// ------------------------------------------------------------
class MinPriorityQueue {
  private heap: { node: string; priority: number }[] = [];

  enqueue(node: string, priority: number): void {
    this.heap.push({ node, priority });
    this.bubbleUp(this.heap.length - 1);
  }

  dequeue(): { node: string; priority: number } | null {
    if (this.heap.length === 0) return null;
    const min = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return min;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.heap[parentIndex].priority <= this.heap[index].priority) break;
      [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
      index = parentIndex;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;
    while (true) {
      let smallest = index;
      const left = 2 * index + 1;
      const right = 2 * index + 2;

      if (left < length && this.heap[left].priority < this.heap[smallest].priority) {
        smallest = left;
      }
      if (right < length && this.heap[right].priority < this.heap[smallest].priority) {
        smallest = right;
      }
      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

// ------------------------------------------------------------
// Core Dijkstra Function
// ------------------------------------------------------------
function dijkstra(graph: Graph, startNode: string, endNode: string): DijkstraResult {
  const distances = new Map<string, number>();
  const previousNodes = new Map<string, string | null>();
  const visited = new Set<string>();
  const pq = new MinPriorityQueue();

  // Initialize all distances to Infinity
  for (const node of graph.keys()) {
    distances.set(node, Infinity);
    previousNodes.set(node, null);
  }

  // The start node costs nothing to reach
  distances.set(startNode, 0);
  pq.enqueue(startNode, 0);

  while (!pq.isEmpty()) {
    const current = pq.dequeue()!;
    const { node: currentNode, priority: currentCost } = current;

    // Skip if already visited (stale entry in PQ)
    if (visited.has(currentNode)) continue;
    visited.add(currentNode);

    // Early exit: we've reached the destination
    if (currentNode === endNode) break;

    // Relax neighbors
    const neighbors = graph.get(currentNode) ?? new Map();
    for (const [neighbor, edgeWeight] of neighbors) {
      if (visited.has(neighbor)) continue;

      const newCost = currentCost + edgeWeight;
      const knownCost = distances.get(neighbor) ?? Infinity;

      if (newCost < knownCost) {
        distances.set(neighbor, newCost);
        previousNodes.set(neighbor, currentNode);
        pq.enqueue(neighbor, newCost); // Lazy deletion — old entry becomes stale
      }
    }
  }

  // Reconstruct the path by backtracking through previousNodes
  const path: string[] = [];
  let current: string | null = endNode;

  while (current !== null) {
    path.unshift(current);
    current = previousNodes.get(current) ?? null;
  }

  // If path doesn't start at startNode, no path exists
  const validPath = path[0] === startNode ? path : [];
  const totalCost = distances.get(endNode) ?? Infinity;

  return { distances, previousNodes, path: validPath, totalCost };
}

// ------------------------------------------------------------
// Helper: Build a bidirectional (undirected) graph
// ------------------------------------------------------------
function buildGraph(edges: [string, string, number][]): Graph {
  const graph: Graph = new Map();

  for (const [from, to, weight] of edges) {
    if (!graph.has(from)) graph.set(from, new Map());
    if (!graph.has(to)) graph.set(to, new Map());

    graph.get(from)!.set(to, weight);
    graph.get(to)!.set(from, weight); // Remove this line for directed graphs
  }

  return graph;
}

