// Types
type NodeId = string;

interface Edge {
  to: NodeId;
  weight: number;
}

interface Graph {
  [node: NodeId]: Edge[];
}

interface ShortestPathResult {
  distances: Record<NodeId, number>;
  previous: Record<NodeId, NodeId | null>;
  getPath: (target: NodeId) => NodeId[];
}

// Min-Heap Priority Queue implementation
class MinHeap {
  private heap: [number, NodeId][] = []; // [distance, nodeId]

  get size(): number {
    return this.heap.length;
  }

  push(distance: number, node: NodeId): void {
    this.heap.push([distance, node]);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): [number, NodeId] | undefined {
    if (this.heap.length === 0) return undefined;

    const min = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return min;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.heap[parentIndex][0] <= this.heap[index][0]) break;
      [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
      index = parentIndex;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left < length && this.heap[left][0] < this.heap[smallest][0]) {
        smallest = left;
      }
      if (right < length && this.heap[right][0] < this.heap[smallest][0]) {
        smallest = right;
      }

      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

// Dijkstra's Algorithm
function dijkstra(graph: Graph, source: NodeId): ShortestPathResult {
  const distances: Record<NodeId, number> = {};
  const previous: Record<NodeId, NodeId | null> = {};
  const visited = new Set<NodeId>();
  const pq = new MinHeap();

  // Initialize all nodes
  for (const node in graph) {
    distances[node] = node === source ? 0 : Infinity;
    previous[node] = null;
  }

  pq.push(0, source);

  while (pq.size > 0) {
    const entry = pq.pop();
    if (!entry) break;

    const [currentDist, currentNode] = entry;

    // Skip if already visited (stale entry in PQ)
    if (visited.has(currentNode)) continue;
    visited.add(currentNode);

    // Early termination: if current distance exceeds known, skip
    if (currentDist > distances[currentNode]) continue;

    // Process neighbors
    const neighbors = graph[currentNode] || [];
    for (const { to, weight } of neighbors) {
      if (visited.has(to)) continue;

      const newDist = distances[currentNode] + weight;

      if (newDist < distances[to]) {
        distances[to] = newDist;
        previous[to] = currentNode;
        pq.push(newDist, to);
      }
    }
  }

  // Helper to reconstruct path
  const getPath = (target: NodeId): NodeId[] => {
    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
    }

    // Return empty if no valid path found
    return path[0] === source ? path : [];
  };

  return { distances, previous, getPath };
}

