function dijkstra(graph: Graph, source: number): ShortestPathResult {
  const distances = new Map<number, number>();
  const previous = new Map<number, number | null>();
  const visited = new Set<number>();
  const pq = new MinHeap();

  // Initialize all distances to Infinity
  for (const node in graph) {
    const n = Number(node);
    distances.set(n, Infinity);
    previous.set(n, null);
  }

  // Distance to source is 0
  distances.set(source, 0);
  pq.push([0, source]);

  while (pq.size > 0) {
    const entry = pq.pop();
    if (!entry) break;

    const [currentDist, currentNode] = entry;

    // Skip if already visited (stale entry in heap)
    if (visited.has(currentNode)) continue;
    visited.add(currentNode);

    // Explore neighbors
    const neighbors = graph[currentNode] ?? [];
    for (const { to, weight } of neighbors) {
      if (visited.has(to)) continue;

      const newDist = currentDist + weight;

      if (newDist < (distances.get(to) ?? Infinity)) {
        distances.set(to, newDist);
        previous.set(to, currentNode);
        pq.push([newDist, to]);
      }
    }
  }

  // Path reconstruction function
  function getPath(target: number): number[] {
    const path: number[] = [];
    let current: number | null | undefined = target;

    while (current !== null && current !== undefined) {
      path.unshift(current);
      current = previous.get(current);
    }

    // If path doesn't start at source, no path exists
    if (path[0] !== source) return [];
    return path;
  }

  return { distances, previous, getPath };
