# LRU Cache Implementation in TypeScript

## Data Structure Choice

The key insight is combining two structures:

```
HashMap + Doubly Linked List = O(1) everything
```

- **HashMap**: O(1) key lookup → points directly to a node
- **Doubly Linked List**: O(1) insertion/deletion (when you have the node reference) → tracks recency order

> *Think of it like a library where the card catalog (HashMap) tells you exactly which shelf (node) a book is on, and the shelves are arranged so the most-recently-read books float to the front automatically.*

---

## Implementation

```typescript
class ListNode<K, V> {
  key: K;
  value: V;
  prev: ListNode<K, V> | null = null;
  next: ListNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

class LRUCache<K, V> {
  private capacity: number;
  private cache: Map<K, ListNode<K, V>>;

  // Sentinel nodes eliminate edge cases for empty list / single element
  private head: ListNode<K, V>; // Most recently used end
  private tail: ListNode<K, V>; // Least recently used end

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new RangeError(`Capacity must be positive, received: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Initialize sentinels with dummy values
    this.head = new ListNode<K, V>(null as K, null as V);
    this.tail = new ListNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── O(1) Get ────────────────────────────────────────────────────────────────

  get(key: K): V | undefined {
    const node = this.cache.get(key);

    if (!node) return undefined;

    // Accessing promotes this node to most-recently-used
    this.moveToFront(node);
    return node.value;
  }

  // ─── O(1) Put ────────────────────────────────────────────────────────────────

  put(key: K, value: V): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update value and promote to front
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU item before inserting if at capacity
    if (this.cache.size >= this.capacity) {
      this.evictLRU();
    }

    const newNode = new ListNode(key, value);
    this.cache.set(key, newNode);
    this.insertAtFront(newNode);
  }

  // ─── Inspection Utilities ─────────────────────────────────────────────────

  get size(): number {
    return this.cache.size;
  }

  has(key: K): boolean {
    return this.cache.has(key);
  }

  /**
   * Returns keys from most-recently-used → least-recently-used.
   * Useful for debugging and testing.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }

    return result;
  }

  peek(key: K): V | undefined {
    return this.cache.get(key)?.value;
  }

  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Private Helpers ──────────────────────────────────────────────────────

  private insertAtFront(node: ListNode<K, V>): void {
    // Insert between head sentinel and current first real node
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: ListNode<K, V>): void {
    // Stitch neighbors together, bypassing this node
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: ListNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lruNode = this.tail.prev;

    // Guard against evicting sentinels (empty cache edge case)
    if (!lruNode || lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key);
  }
}
