# LRU Cache Implementation in TypeScript

## Data Structure Choice

**Doubly Linked List + HashMap** is the optimal combination:

- **HashMap** (`Map<key, node>`) → O(1) lookup by key
- **Doubly Linked List** → O(1) insertion/deletion when you have a node reference
- Together they achieve O(1) for both `get` and `put`

A singly linked list would require O(n) deletion (need previous node). An array would require O(n) shifts.

```typescript
// ─── Node definition ────────────────────────────────────────────────────────

interface LRUNode<K, V> {
  key: K;
  value: V;
  prev: LRUNode<K, V> | null;
  next: LRUNode<K, V> | null;
}

function createNode<K, V>(key: K, value: V): LRUNode<K, V> {
  return { key, value, prev: null, next: null };
}

// ─── LRU Cache ───────────────────────────────────────────────────────────────

class LRUCache<K = number, V = number> {
  private readonly capacity: number;
  private readonly map: Map<K, LRUNode<K, V>>;

  // Sentinel nodes eliminate null checks on every insert/remove
  // Layout: head <-> [MRU ... LRU] <-> tail
  private readonly head: LRUNode<K, V>; // Most-recently-used end
  private readonly tail: LRUNode<K, V>; // Least-recently-used end

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels hold no real data — they just anchor the list
    this.head = createNode<K, V>(null as unknown as K, null as unknown as V);
    this.tail = createNode<K, V>(null as unknown as K, null as unknown as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Public API ─────────────────────────────────────────────────────────────

  /**
   * Returns the value for `key`, or -1 if not present.
   * Marks the entry as most-recently-used.
   * O(1)
   */
  get(key: K): V | -1 {
    const node = this.map.get(key);
    if (!node) return -1;

    this.moveToFront(node);
    return node.value;
  }

  /**
   * Inserts or updates `key` with `value`.
   * If at capacity, evicts the least-recently-used entry first.
   * O(1)
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update value and promote to MRU
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU before inserting if at capacity
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    const node = createNode(key, value);
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  /**
   * Removes a specific key. Returns true if the key existed.
   * O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Removes all entries. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /** Current number of entries. */
  get size(): number {
    return this.map.size;
  }

  /** Iterates from MRU → LRU (for debugging / serialisation). */
  entries(): [K, V][] {
    const result: [K, V][] = [];
    let cur = this.head.next;
    while (cur !== this.tail) {
      result.push([cur!.key, cur!.value]);
      cur = cur!.next;
    }
    return result;
  }

  // ── Private helpers ────────────────────────────────────────────────────────

  /** Splice a node out of its current position. */
  private removeNode(node: LRUNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Null out pointers to avoid memory retention
    node.prev = null;
    node.next = null;
  }

  /** Insert a node immediately after the head sentinel (MRU position). */
  private insertAtFront(node: LRUNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Remove from current position and reinsert at MRU end. */
  private moveToFront(node: LRUNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Remove the node just before the tail sentinel (LRU position). */
  private evictLRU(): void {
    const lru = this.tail.prev!;
    // Guard: list is empty (shouldn't happen if capacity ≥ 1, but be safe)
    if (lru === this.head) return;

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}
