## Implementation

```typescript
// ============================================================
// Core Node structure for the doubly linked list
// ============================================================
class LRUNode<K, V> {
  key: K;
  value: V;
  prev: LRUNode<K, V> | null = null;
  next: LRUNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

// ============================================================
// LRU Cache — O(1) get and put
// ============================================================
class LRUCache<K, V> {
  private capacity: number;
  private map: Map<K, LRUNode<K, V>>;

  // Sentinel nodes eliminate null checks at list boundaries
  //   head.next → most recently used
  //   tail.prev → least recently used
  private head: LRUNode<K, V>;
  private tail: LRUNode<K, V>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer (got ${capacity})`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels — keys/values are never exposed externally
    this.head = new LRUNode<K, V>(null as K, null as V);
    this.tail = new LRUNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ----------------------------------------------------------
  // get: Return the value or undefined; mark as most recent
  // ----------------------------------------------------------
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    // Promote to front (most recently used)
    this.moveToFront(node);
    return node.value;
  }

  // ----------------------------------------------------------
  // put: Insert or update a key; evict LRU if over capacity
  // ----------------------------------------------------------
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update value in-place and promote
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict the least recently used node before inserting
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const newNode = new LRUNode(key, value);
    this.map.set(key, newNode);
    this.insertAtFront(newNode);
  }

  // ----------------------------------------------------------
  // peek: Read a value WITHOUT changing recency order
  // ----------------------------------------------------------
  peek(key: K): V | undefined {
    return this.map.get(key)?.value;
  }

  // ----------------------------------------------------------
  // delete: Explicitly remove a key
  // ----------------------------------------------------------
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  // ----------------------------------------------------------
  // has: Check existence without affecting recency
  // ----------------------------------------------------------
  has(key: K): boolean {
    return this.map.has(key);
  }

  // ----------------------------------------------------------
  // clear: Reset the cache entirely
  // ----------------------------------------------------------
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ----------------------------------------------------------
  // Accessors
  // ----------------------------------------------------------
  get size(): number {
    return this.map.size;
  }

  get maxCapacity(): number {
    return this.capacity;
  }

  // Returns entries from most-recent to least-recent
  entries(): Array<[K, V]> {
    const result: Array<[K, V]> = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push([current!.key, current!.value]);
      current = current!.next;
    }
    return result;
  }

  // ----------------------------------------------------------
  // Private helpers — all O(1)
  // ----------------------------------------------------------

  /** Remove a node from its current list position */
  private removeNode(node: LRUNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Nullify pointers to prevent memory leaks
    node.prev = null;
    node.next = null;
  }

  /** Insert a node immediately after the head sentinel */
  private insertAtFront(node: LRUNode<K, V>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Move an existing node to the front of the list */
  private moveToFront(node: LRUNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Remove the node just before the tail sentinel (LRU item) */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;
    // Guard: only sentinel remains (capacity = 0 is blocked in constructor)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
