  value: V;
  prev: CacheNode<K, V> | null = null;
  next: CacheNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations.
 *
 * Layout: [HEAD (sentinel)] <-> [MRU] <-> ... <-> [LRU] <-> [TAIL (sentinel)]
 *
 * Sentinel nodes eliminate edge cases for empty list / single node operations.
 */
class LRUCache<K, V> {
  private capacity: number;
  private map: Map<K, CacheNode<K, V>>;
  private head: CacheNode<K, V>; // Sentinel: most-recently-used side
  private tail: CacheNode<K, V>; // Sentinel: least-recently-used side
  private size: number = 0;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes — they never hold real data
    this.head = new CacheNode<K, V>(null as K, null as V);
    this.tail = new CacheNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ---------------------------------------------------------------------------
  // Public API
  // ---------------------------------------------------------------------------

  /**
   * Returns the value for key, or undefined if not present.
   * Marks the entry as most recently used.
   * O(1) time complexity.
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  /**
   * Inserts or updates key-value pair.
   * If capacity is exceeded, evicts the least recently used entry.
   * O(1) time complexity.
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update value and promote to MRU position
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU entry before inserting if at capacity
    if (this.size === this.capacity) {
      this.evictLRU();
    }

    const node = new CacheNode(key, value);
    this.map.set(key, node);
    this.insertAtFront(node);
    this.size++;
  }

  /**
   * Removes a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * O(1) time complexity.
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    this.size--;
    return true;
  }

  /** Removes all entries from the cache. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /** Returns number of entries currently in the cache. */
  get currentSize(): number {
    return this.size;
  }

  /** Returns the cache capacity. */
  get maxCapacity(): number {
    return this.capacity;
  }

  /**
   * Returns keys ordered from most-recently-used to least-recently-used.
   * Useful for debugging/inspection. O(n) time.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ---------------------------------------------------------------------------
  // Private helpers — all O(1)
  // ---------------------------------------------------------------------------

  /** Detaches a node from its current list position. */
  private removeNode(node: CacheNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Nullify pointers to prevent memory leaks / stale references
    node.prev = null;
    node.next = null;
  }

  /** Inserts a node immediately after the head sentinel (MRU position). */
  private insertAtFront(node: CacheNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Moves an existing node to the MRU position. */
  private moveToFront(node: CacheNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Removes the node just before the tail sentinel (LRU entry). */
  private evictLRU(): void {
    const lru = this.tail.prev!;
    // Guard: only evict if there's a real node (not the head sentinel)
    if (lru === this.head) return;

    this.removeNode(lru);
    this.map.delete(lru.key);
    this.size--;
  }
}
