# LRU Cache Implementation in TypeScript

## Data Structure Choice

An LRU Cache requires **O(1)** for both `get` and `put` operations. The optimal combination is:

- **HashMap (Map)**: Provides O(1) key lookup
- **Doubly Linked List**: Provides O(1) insertion and deletion at any node (given a pointer)

Together, the Map stores `key → node` references, and the doubly linked list maintains **usage order** (most recent at head, least recent at tail).

---

## Complete Implementation

```typescript
// Node in the doubly linked list
class DLinkedNode {
  key: number;
  value: number;
  prev: DLinkedNode | null = null;
  next: DLinkedNode | null = null;

  constructor(key: number = 0, value: number = 0) {
    this.key = key;
    this.value = value;
  }
}

class LRUCache {
  private capacity: number;
  private size: number;
  private cache: Map<number, DLinkedNode>;

  // Sentinel head and tail nodes to avoid null checks
  private head: DLinkedNode; // Most recently used side
  private tail: DLinkedNode; // Least recently used side

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("Capacity must be a positive integer");
    }

    this.capacity = capacity;
    this.size = 0;
    this.cache = new Map();

    // Initialize sentinel nodes
    this.head = new DLinkedNode();
    this.tail = new DLinkedNode();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Get value by key. Returns -1 if not found.
   * Moves accessed node to the front (most recently used).
   * Time Complexity: O(1)
   */
  get(key: number): number {
    const node = this.cache.get(key);

    if (!node) {
      return -1; // Cache miss
    }

    // Move to front (mark as recently used)
    this.moveToHead(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * If capacity exceeded, evicts the least recently used entry.
   * Time Complexity: O(1)
   */
  put(key: number, value: number): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update existing node's value and move to front
      existingNode.value = value;
      this.moveToHead(existingNode);
    } else {
      // Create new node and add to front
      const newNode = new DLinkedNode(key, value);
      this.cache.set(key, newNode);
      this.addToHead(newNode);
      this.size++;

      // Evict LRU entry if over capacity
      if (this.size > this.capacity) {
        const lruNode = this.removeTail();
        this.cache.delete(lruNode.key); // Remove from map
        this.size--;
      }
    }
  }

  /**
   * Returns current number of entries in cache.
   */
  getSize(): number {
    return this.size;
  }

  /**
   * Checks if a key exists in cache without affecting usage order.
   */
  has(key: number): boolean {
    return this.cache.has(key);
  }

  /**
   * Clears all entries from the cache.
   */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  // ─── Private Helper Methods ───────────────────────────────────────────────

  /**
   * Add a node right after the head sentinel (most recently used position).
   */
  private addToHead(node: DLinkedNode): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Remove a node from its current position in the list.
   */
  private removeNode(node: DLinkedNode): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  /**
   * Move an existing node to the head (most recently used).
   */
  private moveToHead(node: DLinkedNode): void {
    this.removeNode(node);
    this.addToHead(node);
  }

  /**
   * Remove and return the node just before the tail sentinel (LRU node).
   */
  private removeTail(): DLinkedNode {
    const lruNode = this.tail.prev!;
    this.removeNode(lruNode);
    return lruNode;
  }

  /**
   * Debug: Returns cache contents from MRU to LRU order.
   */
  toArray(): Array<{ key: number; value: number }> {
    const result: Array<{ key: number; value: number }> = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push({ key: current!.key, value: current!.value });
      current = current!.next;
    }
    return result;
  }
}
