# LRU Cache in TypeScript: A Dance of Memory and Time

Think of an LRU cache like a librarian's desk — the books used most recently stay within arm's reach, while the oldest untouched ones get shelved away to make room for new arrivals.

---

## Data Structure Choice: HashMap + Doubly Linked List

The magic lies in combining two structures:
- **HashMap** → O(1) key lookup
- **Doubly Linked List** → O(1) insertion/deletion (no shifting, just pointer rewiring)

Together, they form a perfect symbiosis — the map tells *where* a node lives, the list maintains *temporal order*.

---

## Complete Implementation

```typescript
class LRUNode<K, V> {
  key: K;
  value: V;
  prev: LRUNode<K, V> | null = null;
  next: LRUNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

class LRUCache<K, V> {
  private capacity: number;
  private map: Map<K, LRUNode<K, V>>;

  // Sentinel nodes — the "ghost bookends" of our list
  // head.next = most recently used
  // tail.prev = least recently used
  private head: LRUNode<K, V>;
  private tail: LRUNode<K, V>;

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("Cache capacity must be a positive integer");
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes with dummy values
    this.head = new LRUNode<K, V>(null as unknown as K, null as unknown as V);
    this.tail = new LRUNode<K, V>(null as unknown as K, null as unknown as V);

    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Retrieves a value by key.
   * Promotes the node to "most recently used" position.
   * Returns undefined if key doesn't exist.
   * Time: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);

    if (!node) {
      return undefined; // Cache miss
    }

    // Promote to most recently used
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Inserts or updates a key-value pair.
   * If at capacity, evicts the least recently used entry.
   * Time: O(1)
   */
  put(key: K, value: V): void {
    if (this.map.has(key)) {
      // Update existing node
      const node = this.map.get(key)!;
      node.value = value;
      this.moveToFront(node);
    } else {
      // Create new node
      const newNode = new LRUNode(key, value);
      this.map.set(key, newNode);
      this.addToFront(newNode);

      // Evict LRU if over capacity
      if (this.map.size > this.capacity) {
        this.evictLRU();
      }
    }
  }

  /**
   * Peek at a value without affecting recency order.
   * Useful for read-only inspection.
   */
  peek(key: K): V | undefined {
    return this.map.get(key)?.value;
  }

  /**
   * Check if a key exists without promoting it.
   */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /**
   * Returns current number of cached entries.
   */
  get size(): number {
    return this.map.size;
  }

  /**
   * Clears all cached entries.
   */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Private Helpers ──────────────────────────────────────────────────

  /** Inserts a node right after the head sentinel (most recent position) */
  private addToFront(node: LRUNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Removes a node from its current position in the list */
  private removeNode(node: LRUNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  /** Moves an existing node to the most recently used position */
  private moveToFront(node: LRUNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /** Removes and returns the least recently used node (before tail sentinel) */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard against empty cache (shouldn't happen, but defensive programming)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
