  value: V;
  prev: ListNode<K, V> | null = null;
  next: ListNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

class LRUCache<K = number, V = number> {
  private capacity: number;
  private map: Map<K, ListNode<K, V>>;

  // Sentinel head (MRU side) and tail (LRU side)
  private head: ListNode<K, V>;
  private tail: ListNode<K, V>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError('Capacity must be a positive integer.');
    this.capacity = capacity;
    this.map = new Map();

    // Dummy sentinels simplify edge cases — no null checks on insert/remove
    this.head = new ListNode<K, V>(null as unknown as K, null as unknown as V);
    this.tail = new ListNode<K, V>(null as unknown as K, null as unknown as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /** O(1) — returns the value or -1 if not found. Promotes node to MRU position. */
  get(key: K): V | -1 {
    const node = this.map.get(key);
    if (!node) return -1;
    this.moveToFront(node);
    return node.value;
  }

  /** O(1) — inserts or updates key. Evicts LRU entry when over capacity. */
  put(key: K, value: V): void {
    const existing = this.map.get(key);
    if (existing) {
      existing.value = value;       // Update in-place
      this.moveToFront(existing);
      return;
    }

    const node = new ListNode(key, value);
    this.map.set(key, node);
    this.addToFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  /** Current number of entries. */
  get size(): number {
    return this.map.size;
  }

  // ── Private helpers ────────────────────────────────────────────────

  private addToFront(node: ListNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: ListNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: ListNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev!;   // Node just before sentinel tail
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}
```

