# LRU Cache Implementation in TypeScript

## Data Structure Choice

An LRU cache requires O(1) for both operations, which means:
- **HashMap** alone: O(1) lookup but O(n) for tracking recency
- **Doubly Linked List** alone: O(1) insertion/deletion but O(n) lookup
- **HashMap + Doubly Linked List combined**: O(1) for both ✓

The HashMap stores key → node references, while the linked list maintains access order (MRU at head, LRU at tail).

```typescript
// ============================================================
// Node for the Doubly Linked List
// ============================================================
class DLLNode<K, V> {
  key: K;
  value: V;
  prev: DLLNode<K, V> | null = null;
  next: DLLNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

// ============================================================
// LRU Cache Implementation
// ============================================================
class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, DLLNode<K, V>>;

  // Sentinel nodes eliminate null checks on list boundaries
  // Layout: head <-> [MRU ... LRU] <-> tail
  private readonly head: DLLNode<K, V>; // dummy head (most-recently-used side)
  private readonly tail: DLLNode<K, V>; // dummy tail (least-recently-used side)

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes with placeholder values
    this.head = new DLLNode<K, V>(null as K, null as V);
    this.tail = new DLLNode<K, V>(null as K, null as V);

    // Wire sentinels together
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─────────────────────────────────────────────
  // Public API
  // ─────────────────────────────────────────────

  /**
   * Retrieve a value by key.
   * Marks the entry as most-recently-used.
   * Returns undefined if the key does not exist.
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    // Promote to MRU position
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * If at capacity, evicts the least-recently-used entry first.
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    if (this.map.has(key)) {
      // Update existing entry and promote it
      const node = this.map.get(key)!;
      node.value = value;
      this.moveToFront(node);
      return;
    }

    // Evict LRU entry if at capacity
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    // Insert new node at the MRU position
    const newNode = new DLLNode(key, value);
    this.insertAtFront(newNode);
    this.map.set(key, newNode);
  }

  /**
   * Remove a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * Time: O(1) | Space: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Remove all entries from the cache. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /** Returns the number of entries currently in the cache. */
  get size(): number {
    return this.map.size;
  }

  /** Returns an ordered snapshot [MRU → LRU] for debugging. */
  toArray(): Array<[K, V]> {
    const result: Array<[K, V]> = [];
    let current = this.head.next;
    while (current && current !== this.tail) {
      result.push([current.key, current.value]);
      current = current.next;
    }
    return result;
  }

  // ─────────────────────────────────────────────
  // Private Helpers
  // ─────────────────────────────────────────────

  /** Detach a node from its current position in the list. */
  private removeNode(node: DLLNode<K, V>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    // Avoid memory leaks by clearing dangling pointers
    node.prev = null;
    node.next = null;
  }

  /** Insert a node immediately after the head sentinel (MRU position). */
  private insertAtFront(node: DLLNode<K, V>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Move an existing node to the MRU position. */
  private moveToFront(node: DLLNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Remove the LRU node (just before the tail sentinel) and purge from map. */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;
    // Guard against evicting a sentinel (shouldn't happen if capacity > 0)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
