# LRU Cache Implementation in TypeScript

## Data Structure Choice

The classic O(1) solution combines two structures:

```
HashMap + Doubly Linked List = O(1) LRU Cache

HashMap: key → node (O(1) lookup)
Doubly Linked List: tracks recency order (O(1) insertion/deletion with node reference)

[MRU] head ↔ node ↔ node ↔ node ↔ tail [LRU]
```

The map gives us instant node access; the list lets us reorder without scanning.

---

## Implementation

```typescript
class ListNode<K, V> {
  key: K;
  value: V;
  prev: ListNode<K, V> | null = null;
  next: ListNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

class LRUCache<K, V> {
  private capacity: number;
  private cache: Map<K, ListNode<K, V>>;

  // Sentinel nodes eliminate null checks on boundary operations
  private head: ListNode<K, V>; // Most Recently Used side
  private tail: ListNode<K, V>; // Least Recently Used side

  constructor(capacity: number) {
    if (capacity <= 0) throw new Error("Capacity must be a positive integer");

    this.capacity = Math.floor(capacity); // Guard against floats
    this.cache = new Map();

    // Sentinels: dummy nodes that anchor the list — never evicted
    this.head = new ListNode<K, V>(null as K, null as V);
    this.tail = new ListNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Core Operations ───────────────────────────────────────────────────────

  /**
   * Returns the value for `key`, or undefined if not found.
   * Promotes accessed node to MRU position. O(1)
   */
  get(key: K): V | undefined {
    const node = this.cache.get(key);
    if (!node) return undefined;

    this.promote(node); // Mark as recently used
    return node.value;
  }

  /**
   * Inserts or updates a key-value pair.
   * Evicts LRU entry if at capacity. O(1)
   */
  put(key: K, value: V): void {
    const existing = this.cache.get(key);

    if (existing) {
      existing.value = value;  // Update in place
      this.promote(existing);  // Refresh recency
      return;
    }

    // Evict before inserting to stay within capacity
    if (this.cache.size >= this.capacity) {
      this.evictLRU();
    }

    const newNode = new ListNode(key, value);
    this.cache.set(key, newNode);
    this.insertAtFront(newNode);
  }

  // ─── Inspection ────────────────────────────────────────────────────────────

  /** Current number of entries */
  get size(): number {
    return this.cache.size;
  }

  /** Check existence without affecting recency order */
  peek(key: K): V | undefined {
    return this.cache.get(key)?.value;
  }

  /** Returns keys from MRU → LRU for debugging/visualization */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ─── Private Helpers ───────────────────────────────────────────────────────

  /** Move an existing node to the MRU position */
  private promote(node: ListNode<K, V>): void {
    this.removeFromList(node);
    this.insertAtFront(node);
  }

  /** Insert node directly after head (MRU position) */
  private insertAtFront(node: ListNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Unlink a node from its current position */
  private removeFromList(node: ListNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  /** Remove the LRU node (just before tail) and delete from map */
  private evictLRU(): void {
    const lruNode = this.tail.prev;
    if (!lruNode || lruNode === this.head) return; // Empty cache guard

    this.removeFromList(lruNode);
    this.cache.delete(lruNode.key); // Key stored in node — no reverse map needed
  }
}
