    const newNode = new DLinkedNode(key, value);
    this.map.set(key, newNode);
    this.insertAtFront(newNode);
    this.size++;
  }

  /**
   * Remove a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * O(1) time complexity.
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    this.size--;
    return true;
  }

  /** Check whether a key exists WITHOUT updating recency. */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /** Remove all entries. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /** Current number of entries. */
  get currentSize(): number {
    return this.size;
  }

  /** Maximum capacity. */
  get maxCapacity(): number {
    return this.capacity;
  }

  /**
   * Returns entries ordered from most-recently to least-recently used.
   * Useful for debugging/inspection.
   */
  entries(): Array<[K, V]> {
    const result: Array<[K, V]> = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push([current!.key as K, current!.value as V]);
      current = current!.next;
    }
    return result;
  }

  // ─── Private Helpers ──────────────────────────────────────────────────────

  /** Detach a node from its current list position. */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Leave node.prev/next intact — callers may reuse the node
  }

  /** Insert a node immediately after the head sentinel (MRU position). */
  private insertAtFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Combined remove + insert: marks node as most-recently used. */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Remove and unregister the least-recently used node (before tail). */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;
    // Guard: if list is empty (only sentinels), do nothing
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key as K);
    this.size--;
