// ─── Node Definition ────────────────────────────────────────────────────────

class DLinkedNode<K, V> {
  key: K | null;
  value: V | null;
  prev: DLinkedNode<K, V> | null = null;
  next: DLinkedNode<K, V> | null = null;

  constructor(key: K | null = null, value: V | null = null) {
    this.key = key;
    this.value = value;
  }
}

// ─── LRU Cache ──────────────────────────────────────────────────────────────

class LRUCache<K = number, V = number> {
  private readonly capacity: number;
  private size: number = 0;

  // HashMap for O(1) key lookup
  private readonly cache: Map<K, DLinkedNode<K, V>> = new Map();

  // Sentinel nodes eliminate null checks on every operation
  // Layout: head <-> [MRU ... LRU] <-> tail
  private readonly head: DLinkedNode<K, V>; // Most Recently Used side
  private readonly tail: DLinkedNode<K, V>; // Least Recently Used side

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }
    this.capacity = capacity;

    // Initialize sentinel nodes
    this.head = new DLinkedNode<K, V>();
    this.tail = new DLinkedNode<K, V>();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ───────────────────────────────────────────────────────────

  /**
   * Returns the value for the key if it exists, otherwise -1.
   * Accessing a key marks it as most recently used.
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | -1 {
    const node = this.cache.get(key);

    if (!node) return -1;

    // Move to MRU position — this key was just accessed
    this.moveToFront(node);
    return node.value as V;
  }

  /**
   * Inserts or updates a key-value pair.
   * If at capacity, evicts the least recently used entry first.
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update value and promote to MRU
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU entry if at capacity
    if (this.size === this.capacity) {
      this.evictLRU();
    }

    // Insert new node at MRU position
    const newNode = new DLinkedNode(key, value);
    this.cache.set(key, newNode);
    this.addToFront(newNode);
    this.size++;
  }

  /**
   * Removes a key from the cache. Returns true if the key existed.
   * Time: O(1) | Space: O(1)
   */
  delete(key: K): boolean {
    const node = this.cache.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.cache.delete(key);
    this.size--;
    return true;
  }

  /** Clears all entries from the cache. */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /** Returns current number of entries. */
  get length(): number {
    return this.size;
  }

  /** Returns true if the key exists (without affecting recency). */
  has(key: K): boolean {
    return this.cache.has(key);
  }

  /** Returns ordered entries from MRU → LRU (for inspection/debugging). */
  entries(): Array<[K, V]> {
    const result: Array<[K, V]> = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push([current!.key as K, current!.value as V]);
      current = current!.next;
    }

    return result;
  }

  // ─── Private Helpers ──────────────────────────────────────────────────────

  /** Removes a node from its current position in the list. */
  private removeNode(node: DLinkedNode<K, V>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
  }

  /** Inserts a node immediately after the head sentinel (MRU position). */
  private addToFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Promotes an existing node to MRU position. */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /** Removes the node just before the tail sentinel (LRU position). */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: if list is empty, sentinels are adjacent — nothing to evict
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key as K);
    this.size--;
  }
}
