# LRU Cache Implementation in TypeScript

## Data Structure Choice

The optimal solution uses a **HashMap + Doubly Linked List** combination:

- **HashMap** → O(1) key lookup
- **Doubly Linked List** → O(1) node removal and insertion (with direct node reference)
- Together they provide O(1) `get` and `put` operations

```
Most Recent                    Least Recent
    ↓                               ↓
[HEAD] ⟷ [node1] ⟷ [node2] ⟷ [TAIL]
             ↑           ↑
         map.get(k1)  map.get(k2)
```

## Implementation

```typescript
/**
 * Doubly Linked List node
 */
class Node<K, V> {
  key: K;
  value: V;
  prev: Node<K, V> | null = null;
  next: Node<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations
 *
 * Invariant: HEAD.next = most recently used, TAIL.prev = least recently used
 */
class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, Node<K, V>>;

  // Sentinel nodes eliminate null checks on boundary conditions
  private readonly head: Node<K, V>; // Dummy head (most recent side)
  private readonly tail: Node<K, V>; // Dummy tail (least recent side)

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes
    this.head = new Node<K, V>(null as K, null as V);
    this.tail = new Node<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Retrieve value by key.
   * Marks the node as most recently used.
   *
   * @returns value if found, undefined otherwise
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);

    if (!node) {
      return undefined;
    }

    // Move to front (most recently used position)
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * Evicts the least recently used item when over capacity.
   *
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existingNode = this.map.get(key);

    if (existingNode) {
      // Update existing node and mark as recently used
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU item before inserting if at capacity
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    // Insert new node at front (most recently used position)
    const newNode = new Node(key, value);
    this.insertAtFront(newNode);
    this.map.set(key, newNode);
  }

  /**
   * Remove a specific key from the cache.
   *
   * @returns true if key existed, false otherwise
   * Time: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);

    if (!node) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /**
   * Check if a key exists WITHOUT updating recency.
   * Useful for read-only existence checks.
   *
   * Time: O(1)
   */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /** Clear all entries */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get size(): number {
    return this.map.size;
  }

  /**
   * Returns keys from most-recently-used to least-recently-used.
   * Useful for debugging and inspection.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }

    return result;
  }

  // ─── Private Helpers ──────────────────────────────────────────────────────

  /**
   * Insert a node immediately after the head sentinel (most recent position).
   */
  private insertAtFront(node: Node<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Unlink a node from its current position in the list.
   */
  private removeNode(node: Node<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Help GC by clearing references
    node.prev = null;
    node.next = null;
  }

  /**
   * Move an existing node to the most-recently-used position.
   */
  private moveToFront(node: Node<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /**
   * Remove the least-recently-used node (just before tail sentinel).
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: only evict if there's a real node (not the head sentinel)
    if (lruNode === this.head) {
      return;
    }

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
