  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      if (current!.key !== null) result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ============================================================
  // Private LinkedList Operations
  // ============================================================

  /** Insert node right after the head sentinel */
  private addToFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Detach a node from its current position */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  /** Detach + reinsert at front in O(1) */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /** Remove and return the node just before tail (LRU item) */
  private removeLRU(): DLinkedNode<K, V> | null {
    if (this.tail.prev === this.head) return null; // empty list
    const lru = this.tail.prev!;
    this.removeNode(lru);
    return lru;
  }
}

