    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes — they never hold real data
    this.head = createNode<K, V>(null as K, null as V);
    this.tail = createNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  /**
   * Returns the value for `key`, or `undefined` if not present.
   * Marks the accessed entry as most recently used.
   * Time complexity: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);

    if (node === undefined) {
      return undefined;
    }

    // Promote to MRU position
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Inserts or updates the value for `key`.
   * If capacity is exceeded, evicts the least recently used entry.
   * Time complexity: O(1)
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing !== undefined) {
      // Update in-place and promote — no size change
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU entry before inserting if at capacity
    if (this.size === this.capacity) {
      this.evictLRU();
    }

    const node = createNode(key, value);
    this.map.set(key, node);
    this.insertAtFront(node);
    this.size++;
  }

  /**
   * Removes a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * Time complexity: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);

    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.map.delete(key);
    this.size--;
    return true;
  }

  /**
   * Removes all entries from the cache.
   * Time complexity: O(n) — must clear all map entries
   */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /**
   * Returns true if the key exists in the cache WITHOUT updating recency.
   * Useful for read-only existence checks.
   * Time complexity: O(1)
   */
  has(key: K): boolean {
    return this.map.has(key);
  }

  get currentSize(): number {
    return this.size;
  }

  get maxCapacity(): number {
    return this.capacity;
  }

  /**
   * Returns keys ordered from most-recently-used to least-recently-used.
   * Useful for debugging and inspection.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }

    return result;
  }

  // ─── Private Helpers ───────────────────────────────────────────────────────

  /** Detaches a node from its current position in the list. */
  private removeNode(node: DLinkedNode<K, V>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    // Null out pointers to prevent memory leaks / stale references
    node.prev = null;
    node.next = null;
  }

  /** Inserts a node directly after the head sentinel (MRU position). */
  private insertAtFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Moves an existing node to the MRU position. */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Removes the node just before the tail sentinel (LRU position). */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard against evicting a sentinel (only possible if capacity is 0,
    // which we prevent in the constructor)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
    this.size--;
  }
}

