## Implementation

```typescript
// ============================================================
// Node: Building block of the doubly linked list
// ============================================================
class ListNode<K, V> {
  key: K;
  value: V;
  prev: ListNode<K, V> | null = null;
  next: ListNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

// ============================================================
// LRU Cache: O(1) get and put using HashMap + Doubly Linked List
// ============================================================
class LRUCache<K, V> {
  private capacity: number;
  private cache: Map<K, ListNode<K, V>>;

  // Sentinel nodes eliminate null checks at list boundaries
  private head: ListNode<K, V>; // dummy head (most recently used side)
  private tail: ListNode<K, V>; // dummy tail (least recently used side)

  constructor(capacity: number) {
    if (capacity <= 0 || !Number.isInteger(capacity)) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Initialize sentinel nodes — they never hold real data
    this.head = new ListNode<K, V>(null as K, null as V);
    this.tail = new ListNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ------------------------------------------------------------
  // GET: Return value if key exists, otherwise return null
  // Side effect: moves accessed node to front (most recent)
  // Time: O(1) | Space: O(1)
  // ------------------------------------------------------------
  get(key: K): V | null {
    const node = this.cache.get(key);

    if (!node) {
      return null; // Cache miss
    }

    // Promote to most-recently-used position
    this.moveToFront(node);
    return node.value;
  }

  // ------------------------------------------------------------
  // PUT: Insert or update a key-value pair
  // Time: O(1) | Space: O(1)
  // ------------------------------------------------------------
  put(key: K, value: V): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update existing node's value and promote it
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Create new node and insert at front
    const newNode = new ListNode(key, value);
    this.cache.set(key, newNode);
    this.insertAtFront(newNode);

    // Evict least-recently-used entry if over capacity
    if (this.cache.size > this.capacity) {
      this.evictLRU();
    }
  }

  // ------------------------------------------------------------
  // DELETE: Explicitly remove a key from the cache
  // Time: O(1) | Space: O(1)
  // ------------------------------------------------------------
  delete(key: K): boolean {
    const node = this.cache.get(key);

    if (!node) {
      return false; // Key not found
    }

    this.removeNode(node);
    this.cache.delete(key);
    return true;
  }

  // ------------------------------------------------------------
  // PEEK: Read value without affecting recency order
  // Time: O(1) | Space: O(1)
  // ------------------------------------------------------------
  peek(key: K): V | null {
    return this.cache.get(key)?.value ?? null;
  }

  // ------------------------------------------------------------
  // Utility Getters
  // ------------------------------------------------------------
  get size(): number {
    return this.cache.size;
  }

  has(key: K): boolean {
    return this.cache.has(key);
  }

  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // Returns keys from most-recently-used to least-recently-used
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }

    return result;
  }

  // ------------------------------------------------------------
  // Private: Doubly Linked List Operations
  // ------------------------------------------------------------

  // Remove a node from its current position in the list
  private removeNode(node: ListNode<K, V>): void {
    const prevNode = node.prev!;
    const nextNode = node.next!;

    prevNode.next = nextNode;
    nextNode.prev = prevNode;

    // Prevent memory leaks by clearing dangling pointers
    node.prev = null;
    node.next = null;
  }

  // Insert a node directly after the head sentinel (most recent position)
  private insertAtFront(node: ListNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;

    this.head.next!.prev = node;
    this.head.next = node;
  }

  // Combine remove + insertAtFront for accessed nodes
  private moveToFront(node: ListNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  // Remove the node just before the tail sentinel (least recently used)
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: only evict if it's a real node (not the head sentinel)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key);
  }
}
