## Implementation

```typescript
// ─── Node Definition ────────────────────────────────────────────────────────

class DLinkedNode<K, V> {
  key: K | null;
  value: V | null;
  prev: DLinkedNode<K, V> | null = null;
  next: DLinkedNode<K, V> | null = null;

  constructor(key: K | null = null, value: V | null = null) {
    this.key = key;
    this.value = value;
  }
}

// ─── LRU Cache ──────────────────────────────────────────────────────────────

class LRUCache<K = number, V = number> {
  private capacity: number;
  private size: number;
  private cache: Map<K, DLinkedNode<K, V>>;
  private head: DLinkedNode<K, V>; // Sentinel: most recently used end
  private tail: DLinkedNode<K, V>; // Sentinel: least recently used end

  constructor(capacity: number) {
    if (capacity <= 0 || !Number.isInteger(capacity)) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.size = 0;
    this.cache = new Map();

    // Sentinel nodes eliminate null checks on every insert/remove
    this.head = new DLinkedNode<K, V>();
    this.tail = new DLinkedNode<K, V>();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Public API ─────────────────────────────────────────────────────────────

  /**
   * O(1) — Returns value or -1 if not found.
   * Promotes accessed node to most-recently-used position.
   */
  get(key: K): V | -1 {
    const node = this.cache.get(key);

    if (!node) return -1;

    // Access promotes node to front
    this.moveToFront(node);
    return node.value as V;
  }

  /**
   * O(1) — Inserts or updates a key-value pair.
   * Evicts least-recently-used entry when over capacity.
   */
  put(key: K, value: V): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update value and promote to front
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    const newNode = new DLinkedNode(key, value);
    this.cache.set(key, newNode);
    this.addToFront(newNode);
    this.size++;

    if (this.size > this.capacity) {
      this.evictLRU();
    }
  }

  /**
   * Returns current number of entries.
   */
  getSize(): number {
    return this.size;
  }

  /**
   * Returns cache capacity.
   */
  getCapacity(): number {
    return this.capacity;
  }

  /**
   * Removes a specific key from the cache. Returns true if found.
   */
  delete(key: K): boolean {
    const node = this.cache.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.cache.delete(key);
    this.size--;
    return true;
  }

  /**
   * Clears all entries from the cache.
   */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /**
   * Returns keys from most-recently-used to least-recently-used.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key as K);
      current = current!.next;
    }

    return result;
  }

  // ── Private Helpers ────────────────────────────────────────────────────────

  /**
   * Inserts node directly after head (most-recently-used position).
   */
  private addToFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Removes node from its current position in the list.
   */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Prevent memory leaks from dangling pointers
    node.prev = null;
    node.next = null;
  }

  /**
   * Combines remove + addToFront for access promotion.
   */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /**
   * Removes the node just before tail (least-recently-used).
   * Also removes its entry from the HashMap.
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: sentinels should never be evicted
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key as K);
    this.size--;
  }
}
