  key: K;
  value: V;
  prev: CacheNode<K, V> | null = null;
  next: CacheNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations.
 *
 * Layout: [HEAD (sentinel)] <-> [MRU] <-> ... <-> [LRU] <-> [TAIL (sentinel)]
 *
 * Sentinel nodes eliminate edge cases for empty list / single node operations.
 */
class LRUCache<K, V> {
  private capacity: number;
  private map: Map<K, CacheNode<K, V>>;
  private head: CacheNode<K, V>; // Sentinel: most-recently-used side
  private tail: CacheNode<K, V>; // Sentinel: least-recently-used side
  private size: number = 0;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes — they never hold real data
    this.head = new CacheNode<K, V>(null as K, null as V);
    this.tail = new CacheNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ---------------------------------------------------------------------------
  // Public API
  // ---------------------------------------------------------------------------

  /**
   * Returns the value for key, or undefined if not present.
   * Marks the entry as most recently used.
   * O(1) time complexity.
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  /**
   * Inserts or updates key-value pair.
   * If capacity is exceeded, evicts the least recently used entry.
   * O(1) time complexity.
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update value and promote to MRU position
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU entry before inserting if at capacity
    if (this.size === this.capacity) {
      this.evictLRU();
    }

    const node = new CacheNode(key, value);
    this.map.set(key, node);
    this.insertAtFront(node);
    this.size++;
  }

