  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /** Returns number of entries currently in the cache. */
  get currentSize(): number {
    return this.size;
  }

  /** Returns the cache capacity. */
  get maxCapacity(): number {
    return this.capacity;
  }

