   * Returns keys ordered from most-recently-used to least-recently-used.
   * Useful for debugging/inspection. O(n) time.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ---------------------------------------------------------------------------
  // Private helpers — all O(1)
  // ---------------------------------------------------------------------------

  /** Detaches a node from its current list position. */
  private removeNode(node: CacheNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Nullify pointers to prevent memory leaks / stale references
    node.prev = null;
    node.next = null;
  }

  /** Inserts a node immediately after the head sentinel (MRU position). */
  private insertAtFront(node: CacheNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
