// ============================================================
// Node for the doubly linked list
// ============================================================
class DLinkedNode<K, V> {
  key: K | null;
  value: V | null;
  prev: DLinkedNode<K, V> | null = null;
  next: DLinkedNode<K, V> | null = null;

  constructor(key: K | null = null, value: V | null = null) {
    this.key = key;
    this.value = value;
  }
}

// ============================================================
// LRU Cache
// ============================================================
class LRUCache<K = number, V = number> {
  private readonly capacity: number;
  private size: number = 0;

  // HashMap: key → node reference (O(1) lookup)
  private readonly map: Map<K, DLinkedNode<K, V>> = new Map();

  // Sentinel nodes: avoid null checks on every operation
  // Layout: head <-> [MRU ... LRU] <-> tail
  private readonly head: DLinkedNode<K, V>; // dummy head (most recent side)
  private readonly tail: DLinkedNode<K, V>; // dummy tail (least recent side)

  constructor(capacity: number) {
    if (capacity <= 0 || !Number.isInteger(capacity)) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;

    // Initialize sentinels and wire them together
    this.head = new DLinkedNode<K, V>();
    this.tail = new DLinkedNode<K, V>();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ----------------------------------------------------------
  // PUBLIC API
  // ----------------------------------------------------------

  /**
   * Retrieve value by key.
   * Marks the entry as most recently used.
   * Returns -1 if the key does not exist.
   * O(1) time.
   */
  get(key: K): V | -1 {
    const node = this.map.get(key);

    if (!node) return -1;

    // Promote to MRU position
    this.moveToFront(node);
    return node.value as V;
  }

  /**
   * Insert or update a key-value pair.
   * If capacity is exceeded, evicts the least recently used entry.
   * O(1) time.
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update value and promote to MRU
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU if at capacity BEFORE inserting
    if (this.size === this.capacity) {
      this.evictLRU();
    }

    // Create and insert new node at MRU position
    const newNode = new DLinkedNode<K, V>(key, value);
    this.map.set(key, newNode);
    this.addToFront(newNode);
    this.size++;
  }

  /**
   * Remove a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * O(1) time.
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    this.size--;
    return true;
  }

  /** Remove all entries. O(n) time. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /** Current number of entries. O(1). */
  get currentSize(): number {
    return this.size;
  }

  /** Max capacity. O(1). */
  get maxCapacity(): number {
    return this.capacity;
  }

  /**
   * Peek at the key without changing recency order.
   * Useful for debugging/inspection.
   */
  peek(key: K): V | -1 {
    return this.map.get(key)?.value ?? -1;
  }

  /**
   * Returns keys in MRU → LRU order.
   * O(n) time — for debugging/testing only.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key as K);
      current = current!.next;
    }
    return result;
  }

  // ----------------------------------------------------------
  // PRIVATE HELPERS
  // ----------------------------------------------------------

  /** Insert node immediately after head (MRU position). O(1). */
  private addToFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Detach node from its current position. O(1). */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Nullify pointers to help GC and catch stale references early
    node.prev = null;
    node.next = null;
  }

  /** Move existing node to MRU position. O(1). */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /** Remove the LRU node (just before tail) and its map entry. O(1). */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: if tail.prev is head, the list is empty (shouldn't happen with capacity > 0)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key as K);
    this.size--;
  }
}
