 * LRU Cache — O(1) get/put via HashMap + Doubly Linked List
 *
 * Mental model: Imagine a queue where:
 * - HEAD = most recently used (the "hot" end)
 * - TAIL = least recently used (the "cold" end, eviction target)
 *
 * Every access "heats up" a node, moving it to HEAD.
 * When capacity is full, we evict from the TAIL — the coldest item.
 */

// ─── Node ────────────────────────────────────────────────────────────────────

class LRUNode<K, V> {
  key: K;
  value: V;
  prev: LRUNode<K, V> | null = null;
  next: LRUNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

// ─── LRU Cache ───────────────────────────────────────────────────────────────

class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, LRUNode<K, V>>;

  // Sentinel nodes — eliminate null checks at list boundaries
  // Layout: head <-> [most recent] <-> ... <-> [least recent] <-> tail
  private head: LRUNode<K, V>; // dummy head (MRU side)
  private tail: LRUNode<K, V>; // dummy tail (LRU side)

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels carry no real data — they're structural anchors
    this.head = new LRUNode<K, V>(null as K, null as V);
    this.tail = new LRUNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  /**
   * Retrieve a value by key.
   * Side effect: marks the node as most recently used.
   * Returns undefined if key doesn't exist (avoids null confusion).
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    this.moveToFront(node); // 🔥 "heat up" this node
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * If key exists: update value + mark as MRU.
   * If new + at capacity: evict LRU before inserting.
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      existing.value = value;       // update in-place
      this.moveToFront(existing);   // re-heat
      return;
    }

    // Evict before inserting to keep size ≤ capacity
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const node = new LRUNode(key, value);
    this.map.set(key, node);
    this.addToFront(node);
  }

  /**
   * Remove a specific key manually.
   * Returns true if the key existed, false otherwise.
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Peek without side effects — useful for debugging/testing */
  peek(key: K): V | undefined {
    return this.map.get(key)?.value;
  }

  get size(): number {
    return this.map.size;
  }

  /** Snapshot of keys from MRU → LRU order */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Private Linked List Operations ────────────────────────────────────────

  /** Insert node immediately after HEAD (MRU position) */
  private addToFront(node: LRUNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Detach a node from its current position */
  private removeNode(node: LRUNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Nullify pointers to prevent memory leaks in long-lived caches
    node.prev = null;
    node.next = null;
  }

  /** The core LRU operation: detach + reinsert at front */
  private moveToFront(node: LRUNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /** Remove the node just before TAIL (LRU position) */
  private evictLRU(): void {
    const lruNode = this.tail.prev;

    // Guard: only sentinels left means cache is somehow empty
    if (!lruNode || lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
