    this.size = 0;
  }

  /** Returns the number of entries currently in the cache. */
  getSize(): number {
    return this.size;
  }

  /** Returns the maximum capacity of the cache. */
  getCapacity(): number {
    return this.capacity;
  }

  /**
   * Returns keys ordered from most-recently-used to least-recently-used.
   * Useful for debugging and inspection.
   * Time: O(n)
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key!);
      current = current!.next;
    }

    return result;
  }

  // ─── Private Helpers ───────────────────────────────────────────────────────

  /**
   * Inserts a node immediately after the head sentinel (MRU position).
   *
   *  Before: HEAD <-> next
   *  After:  HEAD <-> node <-> next
   */
  private insertAtFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Removes a node from its current position in the list.
   *
   *  Before: prev <-> node <-> next
   *  After:  prev <-> next
   */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Null out pointers to help GC and prevent stale references
    node.prev = null;
    node.next = null;
  }

  /** Moves an existing node to the MRU position (front of list). */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /**
   * Removes the least-recently-used node (just before the tail sentinel)
   * and deletes it from the HashMap.
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard against evicting sentinels (shouldn't happen if size > 0)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key!);
    this.size--;
  }
}
