# LRU Cache Implementation in TypeScript

## Data Structure Choice

The optimal approach combines two data structures:
- **HashMap** (`Map<K, Node<K,V>>`) → O(1) key lookup
- **Doubly Linked List** → O(1) node removal and insertion at any position

The list maintains recency order (head = most recent, tail = least recent). When we access or insert a node, we move it to the head. When capacity is exceeded, we evict from the tail.

```typescript
// ─── Node Definition ────────────────────────────────────────────────────────

class DLinkedNode<K, V> {
  key: K | null;
  value: V | null;
  prev: DLinkedNode<K, V> | null = null;
  next: DLinkedNode<K, V> | null = null;

  constructor(key: K | null = null, value: V | null = null) {
    this.key = key;
    this.value = value;
  }
}

// ─── LRU Cache ───────────────────────────────────────────────────────────────

class LRUCache<K = number, V = number> {
  private readonly capacity: number;
  private size: number = 0;
  private map: Map<K, DLinkedNode<K, V>> = new Map();

  // Sentinel nodes eliminate null checks on every operation
  private head: DLinkedNode<K, V>; // dummy head (most recent side)
  private tail: DLinkedNode<K, V>; // dummy tail (least recent side)

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;

    // Initialize sentinel nodes and link them together
    this.head = new DLinkedNode<K, V>();
    this.tail = new DLinkedNode<K, V>();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  /**
   * Retrieve value by key.
   * Returns -1 (or undefined) if key doesn't exist.
   * Marks the accessed node as most recently used.
   * Time: O(1)
   */
  get(key: K): V | -1 {
    const node = this.map.get(key);

    if (!node) return -1;

    // Accessing promotes node to most-recently-used position
    this.moveToHead(node);
    return node.value as V;
  }

  /**
   * Insert or update a key-value pair.
   * If key exists: update value and mark as most recently used.
   * If key is new: insert at head; evict LRU node if over capacity.
   * Time: O(1)
   */
  put(key: K, value: V): void {
    const existingNode = this.map.get(key);

    if (existingNode) {
      // Update existing node in-place and promote it
      existingNode.value = value;
      this.moveToHead(existingNode);
      return;
    }

    const newNode = new DLinkedNode(key, value);
    this.map.set(key, newNode);
    this.addToHead(newNode);
    this.size++;

    if (this.size > this.capacity) {
      const evicted = this.removeTail();
      // evicted.key is never null here; tail sentinel has null key
      this.map.delete(evicted.key as K);
      this.size--;
    }
  }

  /**
   * Remove a specific key from the cache.
   * Returns true if key existed, false otherwise.
   * Time: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    this.size--;
    return true;
  }

  /**
   * Check existence without affecting recency order.
   * Time: O(1)
   */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /**
   * Remove all entries.
   * Time: O(1) — Map.clear() is O(n) internally but expected here
   */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /** Current number of entries */
  get currentSize(): number {
    return this.size;
  }

  /** Return entries from most-recently-used to least-recently-used */
  entries(): Array<[K, V]> {
    const result: Array<[K, V]> = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push([current!.key as K, current!.value as V]);
      current = current!.next;
    }
    return result;
  }

  // ─── Private Linked List Helpers ───────────────────────────────────────────

  /** Insert node immediately after the head sentinel */
  private addToHead(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Unlink a node from its current position */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Null out pointers to prevent memory leaks in long-running processes
    node.prev = null;
    node.next = null;
  }

  /** Remove node and re-insert at head (promotes to most-recently-used) */
  private moveToHead(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.addToHead(node);
  }

  /** Remove and return the node just before the tail sentinel (LRU node) */
  private removeTail(): DLinkedNode<K, V> {
    const lruNode = this.tail.prev!;
    this.removeNode(lruNode);
    return lruNode;
  }
}
