      existing.value = value;        // Update value in-place
      this.promoteToFront(existing); // Refresh recency
      return;
    }

    // Evict before inserting to avoid momentary over-capacity
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    const node = createNode(key, value);
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  /**
   * Remove a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * Time: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Remove all entries without changing capacity. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get size(): number {
    return this.map.size;
  }

  /** Expose current order for debugging (MRU → LRU) */
  toArray(): Array<{ key: K; value: V }> {
    const result: Array<{ key: K; value: V }> = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push({ key: current!.key, value: current!.value });
      current = current!.next;
    }
    return result;
  }

  // ── Private Helpers ─────────────────────────────────────────

  /** Detach a node from its current list position. */
  private removeNode(node: CacheNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Nullify pointers to help GC and catch dangling-ref bugs
    node.prev = null;
    node.next = null;
  }

  /** Insert a (detached) node immediately after head (MRU position). */
  private insertAtFront(node: CacheNode<K, V>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Move an existing node to the MRU position. */
  private promoteToFront(node: CacheNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
