# LRU Cache Implementation in TypeScript

## Data Structure Choice

The key insight is combining two structures:
- **HashMap**: O(1) key lookup
- **Doubly Linked List**: O(1) node removal/insertion (with direct node reference)

Think of it like a library where books are arranged by recent use — the librarian knows exactly where each book is *and* can instantly move it to the "recently used" shelf.

```typescript
// ============================================================
// Core Node & Type Definitions
// ============================================================

interface CacheNode<K, V> {
  key: K;
  value: V;
  prev: CacheNode<K, V> | null;
  next: CacheNode<K, V> | null;
}

interface CacheStats {
  hits: number;
  misses: number;
  evictions: number;
  hitRate: string;
}

// ============================================================
// LRU Cache Implementation
// ============================================================

class LRUCache<K = number, V = number> {
  private readonly capacity: number;
  private map: Map<K, CacheNode<K, V>>;

  // Sentinel nodes eliminate edge cases for empty list / boundary nodes
  // head.next = most recently used
  // tail.prev = least recently used
  private head: CacheNode<K, V>; // Dummy head (MRU side)
  private tail: CacheNode<K, V>; // Dummy tail (LRU side)

  // Observability
  private hits = 0;
  private misses = 0;
  private evictions = 0;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes — they never hold real data
    this.head = this.createNode(null as K, null as V);
    this.tail = this.createNode(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ──────────────────────────────────────────────────────────
  // Public API
  // ──────────────────────────────────────────────────────────

  /**
   * Retrieve a value by key. Returns undefined on cache miss.
   * Moves accessed node to MRU position — O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);

    if (!node) {
      this.misses++;
      return undefined;
    }

    // Promote to most-recently-used position
    this.moveToFront(node);
    this.hits++;
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * Evicts LRU entry if at capacity — O(1)
   */
  put(key: K, value: V): void {
    const existingNode = this.map.get(key);

    if (existingNode) {
      // Update value in-place and promote
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU entry if we're at capacity
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    // Insert new node at MRU position
    const newNode = this.createNode(key, value);
    this.insertAtFront(newNode);
    this.map.set(key, newNode);
  }

  /**
   * Remove a specific key from the cache — O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /**
   * Peek at a value WITHOUT updating recency — O(1)
   */
  peek(key: K): V | undefined {
    return this.map.get(key)?.value;
  }

  /**
   * Check existence without affecting recency — O(1)
   */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /** Clear all entries, reset stats */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.hits = 0;
    this.misses = 0;
    this.evictions = 0;
  }

  get size(): number {
    return this.map.size;
  }

  /**
   * Returns keys from most-recently-used → least-recently-used
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current && current !== this.tail) {
      result.push(current.key);
      current = current.next;
    }
    return result;
  }

  stats(): CacheStats {
    const total = this.hits + this.misses;
    return {
      hits: this.hits,
      misses: this.misses,
      evictions: this.evictions,
      hitRate: total === 0 ? "N/A" : `${((this.hits / total) * 100).toFixed(1)}%`,
    };
  }

  // ──────────────────────────────────────────────────────────
  // Private Helpers — all O(1)
  // ──────────────────────────────────────────────────────────

  private createNode(key: K, value: V): CacheNode<K, V> {
    return { key, value, prev: null, next: null };
  }

  /** Insert node immediately after dummy head (MRU position) */
  private insertAtFront(node: CacheNode<K, V>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Detach node from its current position */
  private removeNode(node: CacheNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Nullify pointers to help GC
    node.prev = null;
    node.next = null;
  }

  /** Detach then re-insert at front */
  private moveToFront(node: CacheNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Remove the node just before dummy tail (LRU position) */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: only sentinel nodes remain (shouldn't happen with capacity > 0)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
    this.evictions++;
  }
}

