// ============================================================
// Node for the Doubly Linked List
// ============================================================
class DLLNode<K, V> {
  key: K;
  value: V;
  prev: DLLNode<K, V> | null = null;
  next: DLLNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

// ============================================================
// LRU Cache
// ============================================================
class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, DLLNode<K, V>>;

  // Sentinel nodes eliminate null checks on every operation.
  // Layout: head <-> [MRU ... LRU] <-> tail
  private readonly head: DLLNode<K, V>; // Most-recently-used end
  private readonly tail: DLLNode<K, V>; // Least-recently-used end

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Use type assertion for sentinel nodes (keys/values are never read)
    this.head = new DLLNode<K, V>(null as unknown as K, null as unknown as V);
    this.tail = new DLLNode<K, V>(null as unknown as K, null as unknown as V);

    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ------------------------------------------------------------
  // PUBLIC API
  // ------------------------------------------------------------

  /**
   * Retrieve a value by key.
   * Promotes the accessed node to MRU position.
   * Returns undefined if the key doesn't exist.
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    this.promote(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * - Update:  refreshes value and promotes to MRU.
   * - Insert:  adds at MRU position; evicts LRU if over capacity.
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      existing.value = value; // Update value in-place
      this.promote(existing); // Move to MRU
      return;
    }

    // Evict before inserting to keep capacity invariant
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    const newNode = new DLLNode(key, value);
    this.map.set(key, newNode);
    this.insertAtHead(newNode);
  }

  /**
   * Remove a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * Time: O(1) | Space: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Remove all entries from the cache. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /** Current number of items in the cache. */
  get size(): number {
    return this.map.size;
  }

  /** Iterate from MRU → LRU (for debugging / inspection). */
  entries(): Array<[K, V]> {
    const result: Array<[K, V]> = [];
    let current = this.head.next;
    while (current && current !== this.tail) {
      result.push([current.key, current.value]);
      current = current.next;
    }
    return result;
  }

  // ------------------------------------------------------------
  // PRIVATE HELPERS
  // ------------------------------------------------------------

  /** Detach a node from its current position and reattach at head (MRU). */
  private promote(node: DLLNode<K, V>): void {
    this.removeNode(node);
    this.insertAtHead(node);
  }

  /** Insert a node immediately after the head sentinel (MRU position). */
  private insertAtHead(node: DLLNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;

    // Non-null assertion: head.next is always at least tail (sentinel invariant)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Splice a node out of the list without affecting the map. */
  private removeNode(node: DLLNode<K, V>): void {
    // Sentinel nodes guarantee prev/next are never null for real nodes
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  /** Remove the LRU node (just before tail sentinel) and delete from map. */
  private evictLRU(): void {
    const lruNode = this.tail.prev;

    // Guard: only evict if there's a real node (not just sentinels touching)
    if (!lruNode || lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
