# LRU Cache Implementation in TypeScript

## Data Structure Choice

An LRU Cache requires **O(1)** for both `get` and `put`. This is achieved by combining:

- **HashMap** (`Map<K, Node<K,V>>`): O(1) key lookup
- **Doubly Linked List**: O(1) insertion/deletion at any position (given a node reference)

The list maintains usage order — **most recently used at the head**, **least recently used at the tail**. When capacity is exceeded, we evict the tail node.

---

## Full Implementation

```typescript
class ListNode<K, V> {
  key: K;
  value: V;
  prev: ListNode<K, V> | null = null;
  next: ListNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

class LRUCache<K, V> {
  private capacity: number;
  private cache: Map<K, ListNode<K, V>>;

  // Sentinel nodes to avoid null checks on head/tail
  private head: ListNode<K, V>; // dummy head (most recent side)
  private tail: ListNode<K, V>; // dummy tail (least recent side)

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("Capacity must be a positive integer");
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Initialize dummy sentinel nodes
    this.head = new ListNode<K, V>(null as unknown as K, null as unknown as V);
    this.tail = new ListNode<K, V>(null as unknown as K, null as unknown as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Get the value for a key.
   * Returns undefined if the key does not exist.
   * Moves the accessed node to the front (most recently used).
   * Time Complexity: O(1)
   */
  get(key: K): V | undefined {
    const node = this.cache.get(key);
    if (!node) return undefined;

    // Move to front — marks as most recently used
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * If key exists: update value and mark as recently used.
   * If key does not exist and cache is full: evict LRU entry first.
   * Time Complexity: O(1)
   */
  put(key: K, value: V): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update value and move to front
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU if at capacity
    if (this.cache.size >= this.capacity) {
      this.evictLRU();
    }

    // Insert new node at front
    const newNode = new ListNode(key, value);
    this.cache.set(key, newNode);
    this.insertAtFront(newNode);
  }

  /**
   * Check if a key exists without updating recency.
   * Time Complexity: O(1)
   */
  has(key: K): boolean {
    return this.cache.has(key);
  }

  /**
   * Delete a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * Time Complexity: O(1)
   */
  delete(key: K): boolean {
    const node = this.cache.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.cache.delete(key);
    return true;
  }

  /**
   * Clear all entries in the cache.
   * Time Complexity: O(1)
   */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Returns the current number of entries.
   */
  get size(): number {
    return this.cache.size;
  }

  /**
   * Returns entries from most-recently-used to least-recently-used.
   */
  entries(): Array<[K, V]> {
    const result: Array<[K, V]> = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push([current!.key, current!.value]);
      current = current!.next;
    }
    return result;
  }

  // ─── Private Helpers ────────────────────────────────────────────────────────

  /** Remove a node from its current position in the list. */
  private removeNode(node: ListNode<K, V>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  /** Insert a node right after the dummy head (most recently used position). */
  private insertAtFront(node: ListNode<K, V>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Move an existing node to the front of the list. */
  private moveToFront(node: ListNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Remove the least-recently-used node (just before dummy tail). */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;
    if (lruNode === this.head) return; // Cache is empty (shouldn't happen)
    this.removeNode(lruNode);
    this.cache.delete(lruNode.key);
  }
}
