# LRU Cache Implementation in TypeScript

## Data Structure Choice Explanation

The optimal data structure combination for O(1) LRU cache operations is:

1. **HashMap (Map)** — Provides O(1) key lookup, insertion, and deletion
2. **Doubly Linked List** — Provides O(1) node removal and insertion at any position (given a pointer to the node)

**Why this combination?**
- A HashMap alone can't track access order efficiently
- A singly linked list would require O(n) traversal to find predecessors for removal
- Together, the Map stores `key → node` references, and the doubly linked list maintains LRU order (most recent at head, least recent at tail)

---

## Complete Implementation

```typescript
// Node in the doubly linked list
class DLinkedNode {
  key: number;
  value: number;
  prev: DLinkedNode | null = null;
  next: DLinkedNode | null = null;

  constructor(key: number = 0, value: number = 0) {
    this.key = key;
    this.value = value;
  }
}

class LRUCache {
  private capacity: number;
  private size: number;
  private cache: Map<number, DLinkedNode>;

  // Sentinel nodes eliminate null checks on head/tail operations
  private head: DLinkedNode; // dummy head (most recently used side)
  private tail: DLinkedNode; // dummy tail (least recently used side)

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("LRU Cache capacity must be a positive integer");
    }

    this.capacity = capacity;
    this.size = 0;
    this.cache = new Map();

    // Initialize sentinel nodes
    this.head = new DLinkedNode();
    this.tail = new DLinkedNode();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Get the value of a key if it exists.
   * Moves the accessed node to the front (most recently used).
   * Returns -1 if the key does not exist.
   * Time Complexity: O(1)
   */
  get(key: number): number {
    const node = this.cache.get(key);

    if (!node) {
      return -1; // Key not found
    }

    // Move accessed node to head (mark as most recently used)
    this.moveToHead(node);

    return node.value;
  }

  /**
   * Insert or update a key-value pair in the cache.
   * If the cache is at capacity, evict the least recently used item first.
   * Time Complexity: O(1)
   */
  put(key: number, value: number): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Key exists: update value and move to head
      existingNode.value = value;
      this.moveToHead(existingNode);
    } else {
      // Key doesn't exist: create new node
      const newNode = new DLinkedNode(key, value);

      this.cache.set(key, newNode);
      this.addToHead(newNode);
      this.size++;

      // Evict LRU item if over capacity
      if (this.size > this.capacity) {
        const lruNode = this.removeTail();

        if (lruNode) {
          this.cache.delete(lruNode.key);
          this.size--;
        }
      }
    }
  }

  // ─── Private Helper Methods ──────────────────────────────────────────────────

  /**
   * Add a node immediately after the dummy head (most recently used position).
   */
  private addToHead(node: DLinkedNode): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Remove a node from its current position in the linked list.
   */
  private removeNode(node: DLinkedNode): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Clean up references to help GC
    node.prev = null;
    node.next = null;
  }

  /**
   * Move an existing node to the head (mark as most recently used).
   */
  private moveToHead(node: DLinkedNode): void {
    this.removeNode(node);
    this.addToHead(node);
  }

  /**
   * Remove and return the node just before the dummy tail (LRU item).
   * Returns null if the list is empty.
   */
  private removeTail(): DLinkedNode | null {
    const lruNode = this.tail.prev;

    // Guard: if lruNode is the dummy head, list is empty
    if (!lruNode || lruNode === this.head) {
      return null;
    }

    this.removeNode(lruNode);
    return lruNode;
  }

  // ─── Utility / Debug Methods ─────────────────────────────────────────────────

  /**
   * Returns the current number of items in the cache.
   */
  getSize(): number {
    return this.size;
  }

  /**
   * Returns the cache capacity.
   */
  getCapacity(): number {
    return this.capacity;
  }

  /**
   * Returns all keys in order from most recently used to least recently used.
   * Useful for debugging. Time Complexity: O(n)
   */
  getOrderedKeys(): number[] {
    const keys: number[] = [];
    let current = this.head.next;

    while (current && current !== this.tail) {
      keys.push(current.key);
      current = current.next;
    }

    return keys;
  }

  /**
   * Clears all entries from the cache.
   */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }
}
